import java.util.LinkedList;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Implements PRD §13 FR-6 — carry-forward logic.
 *
 * <p>
 * A carry-forward copies a commit's core fields into a new commit in a target
 * week's plan, preserving provenance via a {@link CarryForwardLink}. The streak
 * counter tracks how many consecutive weeks a commit has been carried forward.
 */
@Service
@Transactional
public class CarryForwardService {

	private static final Logger log = LoggerFactory.getLogger(CarryForwardService.class);

	/** Streak threshold at which a repeated-carry-forward reminder is sent. */
	static final int CARRY_FORWARD_REMINDER_THRESHOLD = 2;

	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final UserAccountRepository userRepo;
	private final CarryForwardLinkRepository linkRepo;
	private final ScopeChangeEventRepository scopeChangeEventRepo;
	private final NotificationService notificationService;
	private final ReadModelRefreshService readModelRefreshService;

	public CarryForwardService(WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo,
			UserAccountRepository userRepo, CarryForwardLinkRepository linkRepo,
			ScopeChangeEventRepository scopeChangeEventRepo, NotificationService notificationService,
			ReadModelRefreshService readModelRefreshService) {
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.userRepo = userRepo;
		this.linkRepo = linkRepo;
		this.scopeChangeEventRepo = scopeChangeEventRepo;
		this.notificationService = notificationService;
		this.readModelRefreshService = readModelRefreshService;
	}

	// -------------------------------------------------------------------------
	// carryForward
	// -------------------------------------------------------------------------

	/**
	 * Carries a commit forward into the target week's plan.
	 *
	 * <ul>
	 * <li>Copies title, description, chess piece, RCDO link, estimate points.</li>
	 * <li>Sets {@code carryForwardSourceId} and increments
	 * {@code carryForwardStreak} (source streak + 1).</li>
	 * <li>New commit is inserted at the bottom of the target plan's priority
	 * order.</li>
	 * <li>If the target week plan does not exist, it is lazily created.</li>
	 * <li>If the target plan is already LOCKED, the commit is added as a post-lock
	 * scope change event (COMMIT_ADDED with carry-forward reason).</li>
	 * </ul>
	 *
	 * @param sourceCommitId
	 *            commit to carry forward
	 * @param targetWeekStart
	 *            Monday of the target week
	 * @param reason
	 *            controlled enum reason
	 * @param reasonText
	 *            optional free-text elaboration
	 * @param actorUserId
	 *            user initiating the operation
	 * @return carry-forward response with new commit and provenance link
	 */
	public CarryForwardResponse carryForward(UUID planId, UUID sourceCommitId, LocalDate targetWeekStart,
			CarryForwardReason reason, String reasonText, UUID actorUserId) {

		WeeklyCommit source = requireCommit(sourceCommitId);
		validateCommitBelongsToPlan(planId, source);
		UUID ownerUserId = source.getOwnerUserId();

		// Get or lazily create the target week plan
		WeeklyPlan targetPlan = getOrCreateTargetPlan(ownerUserId, targetWeekStart);
		boolean postLockAdded = targetPlan.getState() == PlanState.LOCKED;

		// Build the new commit (provenance fields set regardless of plan state)
		WeeklyCommit newCommit = buildNewCommit(source, targetPlan);
		WeeklyCommit saved = commitRepo.save(newCommit);

		// If the target plan is LOCKED, record a scope-change event
		if (postLockAdded) {
			recordCarryForwardScopeChangeEvent(targetPlan.getId(), saved, reason, reasonText, actorUserId);
		}

		// Persist the provenance link
		CarryForwardLink link = new CarryForwardLink();
		link.setSourceCommitId(sourceCommitId);
		link.setTargetCommitId(saved.getId());
		link.setReason(reason);
		link.setReasonNotes(reasonText);
		CarryForwardLink savedLink = linkRepo.save(link);

		// Send REPEATED_CARRY_FORWARD_REMINDER if streak reaches the threshold
		if (saved.getCarryForwardStreak() >= CARRY_FORWARD_REMINDER_THRESHOLD) {
			try {
				notificationService.createNotification(ownerUserId, NotificationEvent.REPEATED_CARRY_FORWARD_REMINDER,
						"Repeated carry-forward detected",
						"\"" + saved.getTitle() + "\" has been carried forward for " + saved.getCarryForwardStreak()
								+ " consecutive week(s). Consider re-scoping or " + "blocking it as a dependency.",
						saved.getId(), "COMMIT");
			} catch (Exception ex) {
				log.warn("Failed to send carry-forward reminder for commit {}: {}", saved.getId(), ex.getMessage());
			}
		}

		// Refresh derived read models for the target plan (fire-and-forget)
		triggerReadModelRefresh(targetPlan.getId());

		return new CarryForwardResponse(CommitResponse.from(saved), CarryForwardLinkResponse.from(savedLink),
				postLockAdded);
	}

	// -------------------------------------------------------------------------
	// getCarryForwardLineage
	// -------------------------------------------------------------------------

	/**
	 * Returns the full carry-forward ancestry chain for {@code commitId}.
	 *
	 * <p>
	 * Traverses both ancestors (via {@code carryForwardSourceId} on the commit
	 * entity) and descendants (via {@link CarryForwardLinkRepository}) to produce a
	 * complete, ordered chain from the oldest ancestor to the youngest descendant.
	 *
	 * @param commitId
	 *            starting commit
	 * @return full lineage ordered oldest-first
	 */
	@Transactional(readOnly = true)
	public CarryForwardLineageResponse getCarryForwardLineage(UUID commitId) {
		requireCommit(commitId);

		List<CarryForwardLink> ancestors = new LinkedList<>();
		UUID cursor = commitId;
		while (true) {
			WeeklyCommit c = commitRepo.findById(cursor).orElse(null);
			if (c == null || c.getCarryForwardSourceId() == null) {
				break;
			}
			Optional<CarryForwardLink> link = linkRepo.findByTargetCommitId(cursor);
			link.ifPresent(l -> ancestors.add(0, l));
			cursor = c.getCarryForwardSourceId();
		}
		UUID rootCommitId = cursor;

		List<CarryForwardLink> descendants = new ArrayList<>();
		cursor = commitId;
		while (true) {
			List<CarryForwardLink> links = linkRepo.findBySourceCommitId(cursor);
			if (links.isEmpty()) {
				break;
			}
			CarryForwardLink next = links.get(0);
			descendants.add(next);
			cursor = next.getTargetCommitId();
		}

		List<CarryForwardLink> chain = new ArrayList<>();
		chain.addAll(ancestors);
		chain.addAll(descendants);

		List<CarryForwardLinkResponse> responses = chain.stream().map(CarryForwardLinkResponse::from).toList();
		return new CarryForwardLineageResponse(rootCommitId, responses);
	}

	@Transactional(readOnly = true)
	public CarryForwardLineageDetailResponse getCarryForwardLineageDetail(UUID commitId) {
		requireCommit(commitId);

		LinkedList<UUID> commitIds = new LinkedList<>();
		UUID cursor = commitId;
		while (true) {
			WeeklyCommit commit = requireCommit(cursor);
			commitIds.addFirst(commit.getId());
			if (commit.getCarryForwardSourceId() == null) {
				break;
			}
			cursor = commit.getCarryForwardSourceId();
		}

		cursor = commitId;
		while (true) {
			List<CarryForwardLink> links = linkRepo.findBySourceCommitId(cursor);
			if (links.isEmpty()) {
				break;
			}
			CarryForwardLink next = links.get(0);
			commitIds.addLast(next.getTargetCommitId());
			cursor = next.getTargetCommitId();
		}

		List<CarryForwardNodeResponse> chain = commitIds.stream().map(this::toCarryForwardNode).toList();
		return new CarryForwardLineageDetailResponse(commitId, chain);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private CarryForwardNodeResponse toCarryForwardNode(UUID commitId) {
		WeeklyCommit commit = requireCommit(commitId);
		WeeklyPlan plan = planRepo.findById(commit.getPlanId())
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + commit.getPlanId()));
		return new CarryForwardNodeResponse(commit.getId(), commit.getPlanId(), plan.getWeekStartDate(),
				commit.getTitle(), commit.getOutcome(), commit.getCarryForwardStreak());
	}

	private void validateCommitBelongsToPlan(UUID planId, WeeklyCommit commit) {
		if (!commit.getPlanId().equals(planId)) {
			throw new PlanValidationException("Commit " + commit.getId() + " does not belong to plan " + planId);
		}
	}

	/**
	 * Fetches an existing plan for the owner+week or lazily creates one. This
	 * mirrors the logic in {@link WeeklyPlanService} but is intentionally
	 * self-contained to avoid a circular service dependency.
	 */
	private WeeklyPlan getOrCreateTargetPlan(UUID ownerUserId, LocalDate targetWeekStart) {
		return planRepo.findByOwnerUserIdAndWeekStartDate(ownerUserId, targetWeekStart)
				.orElseGet(() -> createTargetPlan(ownerUserId, targetWeekStart));
	}

	private WeeklyPlan createTargetPlan(UUID ownerUserId, LocalDate weekStartDate) {
		UserAccount user = userRepo.findById(ownerUserId)
				.orElseThrow(() -> new ResourceNotFoundException("User not found: " + ownerUserId));

		if (user.getHomeTeamId() == null) {
			throw new PlanValidationException(
					"User " + ownerUserId + " has no home team; cannot create a carry-forward plan");
		}

		WeeklyPlan plan = new WeeklyPlan();
		plan.setOwnerUserId(ownerUserId);
		plan.setTeamId(user.getHomeTeamId());
		plan.setWeekStartDate(weekStartDate);
		plan.setState(PlanState.DRAFT);
		plan.setCapacityBudgetPoints(user.getWeeklyCapacityPoints());
		plan.setLockDeadline(weekStartDate.atTime(12, 0).toInstant(ZoneOffset.UTC));
		plan.setReconcileDeadline(weekStartDate.plusDays(7).atTime(10, 0).toInstant(ZoneOffset.UTC));
		return planRepo.save(plan);
	}

	private WeeklyCommit buildNewCommit(WeeklyCommit source, WeeklyPlan targetPlan) {
		WeeklyCommit c = new WeeklyCommit();
		c.setPlanId(targetPlan.getId());
		c.setOwnerUserId(source.getOwnerUserId());
		c.setTitle(source.getTitle());
		c.setDescription(source.getDescription());
		c.setChessPiece(source.getChessPiece());
		c.setRcdoNodeId(source.getRcdoNodeId());
		c.setEstimatePoints(source.getEstimatePoints());
		c.setSuccessCriteria(source.getSuccessCriteria());
		// Provenance
		c.setCarryForwardSourceId(source.getId());
		c.setCarryForwardStreak(source.getCarryForwardStreak() + 1);
		// Bottom of priority order
		c.setPriorityOrder((int) (commitRepo.countByPlanId(targetPlan.getId()) + 1));
		return c;
	}

	/**
	 * Records a COMMIT_ADDED scope-change event when carry-forward targets a LOCKED
	 * plan.
	 */
	private void recordCarryForwardScopeChangeEvent(UUID planId, WeeklyCommit commit, CarryForwardReason reason,
			String reasonText, UUID actorUserId) {
		ScopeChangeEvent event = new ScopeChangeEvent();
		event.setPlanId(planId);
		event.setCommitId(commit.getId());
		event.setCategory(ScopeChangeCategory.COMMIT_ADDED);
		event.setChangedByUserId(
				actorUserId != null ? actorUserId : UUID.fromString("00000000-0000-0000-0000-000000000000"));
		String reasonLabel = "CARRY_FORWARD:" + reason.name() + (reasonText != null ? " — " + reasonText : "");
		event.setReason(reasonLabel);
		event.setPreviousValue(null);
		// Minimal JSON payload matching what ScopeChangeService would produce
		event.setNewValue("{\"carryForward\":true,\"chessPiece\":\""
				+ (commit.getChessPiece() != null ? commit.getChessPiece().name() : "") + "\",\"title\":"
				+ quoteJson(commit.getTitle()) + "}");
		scopeChangeEventRepo.save(event);
	}

	private static String quoteJson(String s) {
		if (s == null) {
			return "null";
		}
		return "\"" + s.replace("\\", "\\\\").replace("\"", "\\\"") + "\"";
	}

	private void triggerReadModelRefresh(UUID planId) {
		try {
			readModelRefreshService.refreshForPlan(planId);
		} catch (Exception ex) {
			log.warn("Failed to refresh read models for plan {}: {}", planId, ex.getMessage());
		}
	}
}

package com.weeklycommit.team.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.domain.entity.CapacityOverride;
import com.weeklycommit.domain.entity.LockSnapshotCommit;
import com.weeklycommit.domain.entity.LockSnapshotHeader;
import com.weeklycommit.domain.entity.ManagerComment;
import com.weeklycommit.domain.entity.ManagerReviewException;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.CommitOutcome;
import com.weeklycommit.domain.enums.ExceptionSeverity;
import com.weeklycommit.domain.enums.ExceptionType;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.enums.ScopeChangeCategory;
import com.weeklycommit.domain.enums.UserRole;
import com.weeklycommit.domain.repository.CapacityOverrideRepository;
import com.weeklycommit.domain.repository.LockSnapshotCommitRepository;
import com.weeklycommit.domain.repository.LockSnapshotHeaderRepository;
import com.weeklycommit.domain.repository.ManagerCommentRepository;
import com.weeklycommit.domain.repository.ManagerReviewExceptionRepository;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.TeamMembershipRepository;
import com.weeklycommit.domain.repository.UserAccountRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.team.dto.CapacityOverrideResponse;
import com.weeklycommit.team.dto.CommentResponse;
import com.weeklycommit.team.dto.ExceptionResponse;
import com.weeklycommit.team.exception.AccessDeniedException;
import java.time.Instant;
import java.time.LocalDate;
import java.util.Comparator;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Manages the manager-review features: exception queue, plan/commit comments,
 * capacity overrides, and exception resolution.
 *
 * <p>
 * Exception detection is idempotent — calling {@code getExceptionQueue}
 * multiple times for the same team + week will not create duplicate records.
 */
@Service
@Transactional
public class ManagerReviewService {

	/** Carry-forward streak threshold for the REPEATED_CARRY_FORWARD exception. */
	static final int REPEATED_CARRY_FORWARD_THRESHOLD = 2;

	/**
	 * Minimum number of scope-change events to trigger HIGH_SCOPE_VOLATILITY.
	 */
	static final int HIGH_VOLATILITY_THRESHOLD = 3;

	/** Percentage increase in points that triggers POST_LOCK_SCOPE_INCREASE. */
	static final double POINTS_INCREASE_THRESHOLD = 0.20;

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ScopeChangeEventRepository scopeChangeRepo;
	private final LockSnapshotHeaderRepository lockHeaderRepo;
	private final LockSnapshotCommitRepository lockCommitRepo;
	private final ManagerReviewExceptionRepository exceptionRepo;
	private final ManagerCommentRepository commentRepo;
	private final CapacityOverrideRepository capacityOverrideRepo;
	private final UserAccountRepository userRepo;
	private final TeamMembershipRepository membershipRepo;
	private final AuthorizationService authService;
	private final ObjectMapper objectMapper;

	public ManagerReviewService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			ScopeChangeEventRepository scopeChangeRepo, LockSnapshotHeaderRepository lockHeaderRepo,
			LockSnapshotCommitRepository lockCommitRepo, ManagerReviewExceptionRepository exceptionRepo,
			ManagerCommentRepository commentRepo, CapacityOverrideRepository capacityOverrideRepo,
			UserAccountRepository userRepo, TeamMembershipRepository membershipRepo, AuthorizationService authService,
			ObjectMapper objectMapper) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.scopeChangeRepo = scopeChangeRepo;
		this.lockHeaderRepo = lockHeaderRepo;
		this.lockCommitRepo = lockCommitRepo;
		this.exceptionRepo = exceptionRepo;
		this.commentRepo = commentRepo;
		this.capacityOverrideRepo = capacityOverrideRepo;
		this.userRepo = userRepo;
		this.membershipRepo = membershipRepo;
		this.authService = authService;
		this.objectMapper = objectMapper;
	}

	// -------------------------------------------------------------------------
	// Exception queue
	// -------------------------------------------------------------------------

	/**
	 * Detects and persists exceptions for all team members' plans in the given
	 * week, then returns the unresolved exception list ordered by severity.
	 *
	 * <p>
	 * Detection is idempotent: existing unresolved exceptions are not duplicated.
	 *
	 * <p>
	 * Ordering: HIGH severity first, then MEDIUM, then LOW. Within HIGH,
	 * {@link ExceptionType#KING_CHANGED_POST_LOCK} precedes other HIGH types.
	 *
	 * @param callerId
	 *            must have MANAGER or ADMIN role
	 */
	public List<ExceptionResponse> getExceptionQueue(UUID teamId, LocalDate weekStart, UUID callerId) {
		UserRole role = authService.getCallerRole(callerId);
		if (role == UserRole.IC) {
			throw new AccessDeniedException("Only MANAGER or ADMIN may access the exception queue");
		}

		List<WeeklyPlan> plans = planRepo.findByTeamIdAndWeekStartDate(teamId, weekStart);
		Instant now = Instant.now();

		for (WeeklyPlan plan : plans) {
			detectAndPersistExceptions(plan, teamId, weekStart, now);
		}

		List<ManagerReviewException> exceptions = exceptionRepo.findByTeamIdAndWeekStartDateAndResolved(teamId,
				weekStart, false);

		return exceptions.stream().sorted(exceptionComparator()).map(ExceptionResponse::from).toList();
	}

	// -------------------------------------------------------------------------
	// Add comment
	// -------------------------------------------------------------------------

	/**
	 * Adds a manager comment on a plan or commit.
	 *
	 * @param targetType
	 *            "PLAN" or "COMMIT"
	 * @param targetId
	 *            the plan ID or commit ID
	 * @param managerId
	 *            the commenting manager
	 * @param text
	 *            the comment text
	 * @throws AccessDeniedException
	 *             if the caller is not the direct manager of the target's owner
	 * @throws PlanValidationException
	 *             if {@code targetType} is unknown or the target does not exist
	 */
	public CommentResponse addComment(String targetType, UUID targetId, UUID managerId, String text) {
		if (text == null || text.isBlank()) {
			throw new PlanValidationException("Comment text must not be blank");
		}

		UUID targetOwnerUserId;
		UUID planId = null;
		UUID commitId = null;

		if ("PLAN".equalsIgnoreCase(targetType)) {
			WeeklyPlan plan = planRepo.findById(targetId)
					.orElseThrow(() -> new ResourceNotFoundException("Plan not found: " + targetId));
			targetOwnerUserId = plan.getOwnerUserId();
			planId = targetId;
		} else if ("COMMIT".equalsIgnoreCase(targetType)) {
			WeeklyCommit commit = commitRepo.findById(targetId)
					.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + targetId));
			targetOwnerUserId = commit.getOwnerUserId();
			commitId = targetId;
		} else {
			throw new PlanValidationException("Unknown target type: " + targetType + "; expected PLAN or COMMIT");
		}

		// Only direct managers may comment on direct reports' data
		authService.checkIsDirectManager(managerId, targetOwnerUserId);

		ManagerComment comment = new ManagerComment();
		comment.setPlanId(planId);
		comment.setCommitId(commitId);
		comment.setAuthorUserId(managerId);
		comment.setContent(text);
		ManagerComment saved = commentRepo.save(comment);

		return CommentResponse.from(saved);
	}

	// -------------------------------------------------------------------------
	// Set capacity override
	// -------------------------------------------------------------------------

	/**
	 * Sets (or updates) the capacity budget override for a user for a given week.
	 *
	 * @param managerId
	 *            the manager applying the override
	 * @param userId
	 *            the IC whose capacity is being overridden
	 * @param weekStart
	 *            the target week
	 * @param overridePoints
	 *            the new capacity budget
	 * @param reason
	 *            required explanation for the override
	 * @throws AccessDeniedException
	 *             if the caller is not the direct manager of the target user
	 */
	public CapacityOverrideResponse setCapacityOverride(UUID managerId, UUID userId, LocalDate weekStart,
			int overridePoints, String reason) {
		if (overridePoints <= 0) {
			throw new PlanValidationException("Override points must be positive");
		}

		// Verify managerId is a direct manager of userId
		authService.checkIsDirectManager(managerId, userId);

		// Upsert: update existing override or create a new one
		CapacityOverride override = capacityOverrideRepo.findByUserIdAndWeekStartDate(userId, weekStart)
				.orElse(new CapacityOverride());

		override.setUserId(userId);
		override.setWeekStartDate(weekStart);
		override.setBudgetPoints(overridePoints);
		override.setReason(reason);
		override.setSetByManagerId(managerId);

		CapacityOverride saved = capacityOverrideRepo.save(override);

		// Also update the weekly plan's capacity budget if a plan exists
		planRepo.findByOwnerUserIdAndWeekStartDate(userId, weekStart).ifPresent(plan -> {
			plan.setCapacityBudgetPoints(overridePoints);
			planRepo.save(plan);
		});

		return CapacityOverrideResponse.from(saved);
	}

	// -------------------------------------------------------------------------
	// Resolve exception
	// -------------------------------------------------------------------------

	/**
	 * Marks a manager-review exception as resolved.
	 *
	 * @param exceptionId
	 *            the exception to resolve
	 * @param resolution
	 *            the resolution note
	 * @param resolverId
	 *            the manager/admin resolving the exception
	 * @throws AccessDeniedException
	 *             if the caller is not MANAGER or ADMIN
	 */
	public ExceptionResponse resolveException(UUID exceptionId, String resolution, UUID resolverId) {
		UserRole role = authService.getCallerRole(resolverId);
		if (role == UserRole.IC) {
			throw new AccessDeniedException("Only MANAGER or ADMIN may resolve exceptions");
		}

		ManagerReviewException exception = exceptionRepo.findById(exceptionId)
				.orElseThrow(() -> new ResourceNotFoundException("Exception not found: " + exceptionId));

		if (exception.isResolved()) {
			throw new PlanValidationException("Exception " + exceptionId + " is already resolved");
		}

		if (resolution == null || resolution.isBlank()) {
			throw new PlanValidationException("Resolution text is required to resolve an exception");
		}

		exception.setResolved(true);
		exception.setResolution(resolution);
		exception.setResolvedAt(Instant.now());
		exception.setResolvedById(resolverId);
		ManagerReviewException saved = exceptionRepo.save(exception);

		return ExceptionResponse.from(saved);
	}

	// -------------------------------------------------------------------------
	// Exception detection
	// -------------------------------------------------------------------------

	/**
	 * Detects all applicable exception types for the given plan and persists any
	 * that have not already been recorded (idempotent).
	 */
	void detectAndPersistExceptions(WeeklyPlan plan, UUID teamId, LocalDate weekStart, Instant now) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());
		int totalPoints = commits.stream().filter(c -> c.getOutcome() != CommitOutcome.CANCELED)
				.mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0).sum();

		// --- MISSED_LOCK: still DRAFT past lock deadline ---
		if (plan.getState() == PlanState.DRAFT && now.isAfter(plan.getLockDeadline())) {
			ensureException(teamId, plan.getId(), plan.getOwnerUserId(), ExceptionType.MISSED_LOCK,
					ExceptionSeverity.MEDIUM, weekStart, "Plan was not locked by the deadline");
		}

		// --- AUTO_LOCKED: system locked with or without errors ---
		if (plan.isSystemLockedWithErrors()) {
			ensureException(teamId, plan.getId(), plan.getOwnerUserId(), ExceptionType.AUTO_LOCKED,
					ExceptionSeverity.HIGH, weekStart, "Plan was auto-locked by the system (manual lock was missed)");
		}

		// --- MISSED_RECONCILE: past reconcile deadline and not RECONCILED ---
		if (plan.getState() != PlanState.RECONCILED && now.isAfter(plan.getReconcileDeadline())) {
			ensureException(teamId, plan.getId(), plan.getOwnerUserId(), ExceptionType.MISSED_RECONCILE,
					ExceptionSeverity.MEDIUM, weekStart, "Plan reconciliation was not completed by the deadline");
		}

		// --- OVER_BUDGET: total committed points exceed capacity budget ---
		if (totalPoints > plan.getCapacityBudgetPoints()) {
			ensureException(teamId, plan.getId(), plan.getOwnerUserId(), ExceptionType.OVER_BUDGET,
					ExceptionSeverity.MEDIUM, weekStart, "Total committed points (" + totalPoints
							+ ") exceed capacity budget (" + plan.getCapacityBudgetPoints() + ")");
		}

		// --- REPEATED_CARRY_FORWARD: any commit has streak >= 2 ---
		boolean hasRepeatedCarryForward = commits.stream()
				.anyMatch(c -> c.getCarryForwardStreak() >= REPEATED_CARRY_FORWARD_THRESHOLD);
		if (hasRepeatedCarryForward) {
			int maxStreak = commits.stream().mapToInt(WeeklyCommit::getCarryForwardStreak).max().orElse(0);
			ensureException(teamId, plan.getId(), plan.getOwnerUserId(), ExceptionType.REPEATED_CARRY_FORWARD,
					ExceptionSeverity.LOW, weekStart,
					"One or more commits have been carried forward " + maxStreak + " weeks in a row");
		}

		// --- Scope-change based exceptions (only for non-DRAFT plans) ---
		if (plan.getState() != PlanState.DRAFT) {
			List<ScopeChangeEvent> events = scopeChangeRepo.findByPlanIdOrderByCreatedAtAsc(plan.getId());

			// HIGH_SCOPE_VOLATILITY: more than 3 scope-change events
			if (events.size() > HIGH_VOLATILITY_THRESHOLD) {
				ensureException(teamId, plan.getId(), plan.getOwnerUserId(), ExceptionType.HIGH_SCOPE_VOLATILITY,
						ExceptionSeverity.MEDIUM, weekStart, "Plan has " + events.size()
								+ " scope-change events post-lock (threshold: " + HIGH_VOLATILITY_THRESHOLD + ")");
			}

			// KING_CHANGED_POST_LOCK: King commit added or chess piece changed to/from KING
			if (detectKingChangePostLock(commits, events)) {
				ensureException(teamId, plan.getId(), plan.getOwnerUserId(), ExceptionType.KING_CHANGED_POST_LOCK,
						ExceptionSeverity.HIGH, weekStart,
						"A King-level commit was added or changed after the plan was locked");
			}

			// POST_LOCK_SCOPE_INCREASE: >20% points increase from baseline
			detectPostLockScopeIncrease(plan, commits)
					.ifPresent(description -> ensureException(teamId, plan.getId(), plan.getOwnerUserId(),
							ExceptionType.POST_LOCK_SCOPE_INCREASE, ExceptionSeverity.HIGH, weekStart, description));
		}
	}

	/**
	 * Returns {@code true} if any scope-change event indicates a King commit was
	 * added or a commit was changed to/from KING after lock.
	 */
	boolean detectKingChangePostLock(List<WeeklyCommit> currentCommits, List<ScopeChangeEvent> events) {
		for (ScopeChangeEvent e : events) {
			if (e.getCategory() == ScopeChangeCategory.COMMIT_ADDED) {
				// Check if the new commit (still present) is a KING
				String newVal = e.getNewValue();
				if (newVal != null) {
					try {
						JsonNode node = objectMapper.readTree(newVal);
						if (ChessPiece.KING.name().equals(node.path("chessPiece").asText(null))) {
							return true;
						}
					} catch (JsonProcessingException ignored) {
						// Malformed JSON — fall back to checking current commits by commit ID
					}
				}
				// Also check the current state of the associated commit
				if (e.getCommitId() != null) {
					boolean commitIsKing = currentCommits.stream().filter(c -> c.getId().equals(e.getCommitId()))
							.anyMatch(c -> c.getChessPiece() == ChessPiece.KING);
					if (commitIsKing)
						return true;
				}
			} else if (e.getCategory() == ScopeChangeCategory.CHESS_PIECE_CHANGED) {
				String prev = e.getPreviousValue();
				String next = e.getNewValue();
				if (ChessPiece.KING.name().equals(prev) || ChessPiece.KING.name().equals(next)) {
					return true;
				}
			}
		}
		return false;
	}

	/**
	 * Returns an optional description if post-lock points increased by more than
	 * 20% from the lock baseline.
	 */
	Optional<String> detectPostLockScopeIncrease(WeeklyPlan plan, List<WeeklyCommit> currentCommits) {
		Optional<LockSnapshotHeader> headerOpt = lockHeaderRepo.findByPlanId(plan.getId());
		if (headerOpt.isEmpty())
			return Optional.empty();

		List<LockSnapshotCommit> snapshots = lockCommitRepo.findBySnapshotId(headerOpt.get().getId());
		int baselinePoints = snapshots.stream().mapToInt(sc -> parseEstimatePoints(sc.getSnapshotData())).sum();

		if (baselinePoints <= 0)
			return Optional.empty();

		int currentPoints = currentCommits.stream().filter(c -> c.getOutcome() != CommitOutcome.CANCELED)
				.mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0).sum();

		double increase = (double) (currentPoints - baselinePoints) / baselinePoints;
		if (increase > POINTS_INCREASE_THRESHOLD) {
			return Optional
					.of(String.format("Total estimate points increased %.0f%% from the lock baseline (%d → %d points)",
							increase * 100, baselinePoints, currentPoints));
		}
		return Optional.empty();
	}

	// -------------------------------------------------------------------------
	// Internal helpers
	// -------------------------------------------------------------------------

	/**
	 * Persists a new exception if one with the same plan+type combination doesn't
	 * already exist as unresolved.
	 */
	private void ensureException(UUID teamId, UUID planId, UUID userId, ExceptionType type, ExceptionSeverity severity,
			LocalDate weekStart, String description) {
		Optional<ManagerReviewException> existing = exceptionRepo.findByPlanIdAndExceptionTypeAndResolved(planId, type,
				false);
		if (existing.isPresent())
			return;

		ManagerReviewException exc = new ManagerReviewException();
		exc.setTeamId(teamId);
		exc.setPlanId(planId);
		exc.setUserId(userId);
		exc.setExceptionType(type);
		exc.setSeverity(severity);
		exc.setDescription(description);
		exc.setWeekStartDate(weekStart);
		exceptionRepo.save(exc);
	}

	/**
	 * Comparator for exception ordering: HIGH before MEDIUM before LOW; within
	 * HIGH, KING_CHANGED_POST_LOCK first.
	 */
	private Comparator<ManagerReviewException> exceptionComparator() {
		return Comparator.<ManagerReviewException, Integer>comparing(e -> e.getSeverity().ordinal())
				.thenComparing(e -> e.getExceptionType() == ExceptionType.KING_CHANGED_POST_LOCK ? 0 : 1)
				.thenComparing(e -> e.getExceptionType().ordinal());
	}

	/**
	 * Parses the {@code estimatePoints} field from a lock-snapshot-commit JSON
	 * blob.
	 */
	private int parseEstimatePoints(String snapshotData) {
		if (snapshotData == null)
			return 0;
		try {
			JsonNode node = objectMapper.readTree(snapshotData);
			JsonNode pts = node.path("estimatePoints");
			return pts.isNumber() ? pts.intValue() : 0;
		} catch (JsonProcessingException e) {
			return 0;
		}
	}

	private UserAccount requireUser(UUID userId) {
		return userRepo.findById(userId).orElseThrow(() -> new ResourceNotFoundException("User not found: " + userId));
	}
}

package com.weeklycommit.ticket.service;

import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.entity.WorkItemStatusHistory;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.NotificationEvent;
import com.weeklycommit.domain.enums.TicketPriority;
import com.weeklycommit.domain.enums.TicketStatus;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.domain.repository.WorkItemStatusHistoryRepository;
import com.weeklycommit.notification.service.NotificationService;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.ticket.dto.CreateTicketFromCommitRequest;
import com.weeklycommit.ticket.dto.CreateTicketRequest;
import com.weeklycommit.ticket.dto.LinkedCommitEntry;
import com.weeklycommit.ticket.dto.PagedTicketResponse;
import com.weeklycommit.ticket.dto.TicketDetailResponse;
import com.weeklycommit.ticket.dto.TicketListParams;
import com.weeklycommit.ticket.dto.TicketResponse;
import com.weeklycommit.ticket.dto.TicketStatusHistoryResponse;
import com.weeklycommit.ticket.dto.TicketSummaryResponse;
import com.weeklycommit.ticket.dto.UpdateTicketRequest;
import java.util.EnumSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;
import org.springframework.data.jpa.domain.Specification;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * CRUD and status-workflow service for native tickets (work items).
 */
@Service
@Transactional
public class TicketService {

	private static final Logger log = LoggerFactory.getLogger(TicketService.class);

	/** Valid Fibonacci-scale estimate values (mirrors CommitService). */
	private static final Set<Integer> VALID_ESTIMATE_POINTS = Set.of(1, 2, 3, 5, 8);

	/** Key prefix used when auto-generating ticket keys. */
	private static final String KEY_PREFIX = "T-";

	/** Legal status transitions. */
	private static final Map<TicketStatus, Set<TicketStatus>> ALLOWED_TRANSITIONS = Map.of(TicketStatus.TODO,
			EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.CANCELED), TicketStatus.IN_PROGRESS,
			EnumSet.of(TicketStatus.DONE, TicketStatus.BLOCKED, TicketStatus.CANCELED, TicketStatus.TODO),
			TicketStatus.BLOCKED, EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.CANCELED, TicketStatus.TODO),
			TicketStatus.DONE, EnumSet.noneOf(TicketStatus.class), TicketStatus.CANCELED,
			EnumSet.of(TicketStatus.TODO));

	private final WorkItemRepository workItemRepo;
	private final WorkItemStatusHistoryRepository historyRepo;
	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final NotificationService notificationService;

	public TicketService(WorkItemRepository workItemRepo, WorkItemStatusHistoryRepository historyRepo,
			WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo, NotificationService notificationService) {
		this.workItemRepo = workItemRepo;
		this.historyRepo = historyRepo;
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.notificationService = notificationService;
	}

	// -------------------------------------------------------------------------
	// Create
	// -------------------------------------------------------------------------

	public TicketDetailResponse createTicket(CreateTicketRequest req) {
		validateEstimatePoints(req.estimatePoints());

		WorkItem item = new WorkItem();
		item.setTeamId(req.teamId());
		item.setKey(generateKey(req.teamId()));
		item.setTitle(req.title());
		item.setDescription(req.description());
		item.setStatus(req.status() != null ? req.status() : TicketStatus.TODO);
		item.setPriority(req.priority() != null ? req.priority() : TicketPriority.MEDIUM);
		item.setAssigneeUserId(req.assigneeUserId());
		item.setReporterUserId(req.reporterUserId());
		item.setEstimatePoints(req.estimatePoints());
		item.setRcdoNodeId(req.rcdoNodeId());
		item.setTargetWeekStartDate(req.targetWeekStartDate());

		WorkItem saved = workItemRepo.save(item);
		return getTicketDetail(saved.getId());
	}

	public TicketDetailResponse createTicketFromCommit(CreateTicketFromCommitRequest req) {
		WeeklyPlan plan = requirePlan(req.planId());
		WeeklyCommit commit = requireCommit(req.commitId());
		if (!commit.getPlanId().equals(plan.getId())) {
			throw new PlanValidationException("Commit " + req.commitId() + " does not belong to plan " + req.planId());
		}

		WorkItem item = new WorkItem();
		UUID teamId = req.teamId() != null ? req.teamId() : plan.getTeamId();
		item.setTeamId(teamId);
		item.setKey(generateKey(teamId));
		item.setTitle(req.title() != null && !req.title().isBlank() ? req.title() : commit.getTitle());
		item.setDescription(req.description() != null ? req.description() : commit.getDescription());
		item.setStatus(req.status() != null ? req.status() : TicketStatus.TODO);
		item.setPriority(req.priority() != null ? req.priority() : TicketPriority.MEDIUM);
		item.setAssigneeUserId(req.assigneeUserId());
		item.setReporterUserId(req.reporterUserId() != null ? req.reporterUserId() : commit.getOwnerUserId());
		validateEstimatePoints(req.estimatePoints() != null ? req.estimatePoints() : commit.getEstimatePoints());
		item.setEstimatePoints(req.estimatePoints() != null ? req.estimatePoints() : commit.getEstimatePoints());
		item.setRcdoNodeId(req.rcdoNodeId() != null ? req.rcdoNodeId() : commit.getRcdoNodeId());
		item.setTargetWeekStartDate(
				req.targetWeekStartDate() != null ? req.targetWeekStartDate() : plan.getWeekStartDate());

		WorkItem saved = workItemRepo.save(item);
		return getTicketDetail(saved.getId());
	}

	// -------------------------------------------------------------------------
	// Read
	// -------------------------------------------------------------------------

	@Transactional(readOnly = true)
	public TicketDetailResponse getTicketDetail(UUID id) {
		WorkItem ticket = requireTicket(id);
		TicketResponse base = TicketResponse.from(ticket);

		List<TicketStatusHistoryResponse> statusHistory = historyRepo.findByWorkItemIdOrderByCreatedAtAsc(id).stream()
				.map(TicketStatusHistoryResponse::from).toList();

		List<LinkedCommitEntry> linkedCommits = commitRepo.findByWorkItemId(id).stream().map(commit -> {
			WeeklyPlan plan = planRepo.findById(commit.getPlanId()).orElse(null);
			if (plan == null) {
				return null;
			}
			return new LinkedCommitEntry(commit.getId(), commit.getPlanId(), commit.getTitle(), commit.getChessPiece(),
					commit.getEstimatePoints(), plan.getWeekStartDate(), commit.getOutcome());
		}).filter(java.util.Objects::nonNull).toList();

		return TicketDetailResponse.from(base, statusHistory, linkedCommits);
	}

	@Transactional(readOnly = true)
	public PagedTicketResponse listTickets(TicketListParams params) {
		Specification<WorkItem> spec = buildSpecification(params);
		Pageable pageable = PageRequest.of(params.normalizedPage() - 1, params.normalizedPageSize(),
				buildSort(params.normalizedSortBy(), params.normalizedSortDir()));
		Page<WorkItem> page = workItemRepo.findAll(spec, pageable);
		return new PagedTicketResponse(page.getContent().stream().map(TicketSummaryResponse::from).toList(),
				page.getTotalElements(), params.normalizedPage(), params.normalizedPageSize());
	}

	@Transactional(readOnly = true)
	public List<TicketSummaryResponse> listTicketSummaries(UUID teamId) {
		Specification<WorkItem> spec = (root, query,
				cb) -> teamId == null ? cb.conjunction() : cb.equal(root.get("teamId"), teamId);
		return workItemRepo.findAll(spec, Sort.by(Sort.Direction.DESC, "updatedAt")).stream()
				.map(TicketSummaryResponse::from).toList();
	}

	// -------------------------------------------------------------------------
	// Update
	// -------------------------------------------------------------------------

	public TicketDetailResponse updateTicket(UUID id, UpdateTicketRequest req, UUID actorUserId) {
		WorkItem item = requireTicket(id);

		if (req.title() != null && !req.title().isBlank()) {
			item.setTitle(req.title());
		}
		if (req.description() != null) {
			item.setDescription(req.description());
		}
		if (req.priority() != null) {
			item.setPriority(req.priority());
		}
		if (req.assigneeUserId() != null) {
			item.setAssigneeUserId(req.assigneeUserId());
		}
		if (req.teamId() != null) {
			item.setTeamId(req.teamId());
		}
		if (req.estimatePoints() != null) {
			validateEstimatePoints(req.estimatePoints());
			item.setEstimatePoints(req.estimatePoints());
		}
		if (req.rcdoNodeId() != null) {
			item.setRcdoNodeId(req.rcdoNodeId());
		}
		if (req.targetWeekStartDate() != null) {
			item.setTargetWeekStartDate(req.targetWeekStartDate());
		}
		if (req.status() != null) {
			transitionStatus(item, req.status(), actorUserId != null ? actorUserId : item.getReporterUserId());
		}

		workItemRepo.save(item);
		return getTicketDetail(item.getId());
	}

	// -------------------------------------------------------------------------
	// Update status
	// -------------------------------------------------------------------------

	public TicketDetailResponse updateStatus(UUID id, TicketStatus newStatus, UUID changedByUserId) {
		WorkItem item = requireTicket(id);
		transitionStatus(item, newStatus, changedByUserId);
		workItemRepo.save(item);

		// Notify commit owner(s) when a ticket linked to a King or Queen commit is
		// blocked
		if (newStatus == TicketStatus.BLOCKED) {
			try {
				notifyCriticalTicketBlocked(item);
			} catch (Exception ex) {
				log.warn("Failed to send CRITICAL_TICKET_BLOCKED notification for ticket {}: {}", id, ex.getMessage());
			}
		}

		return getTicketDetail(item.getId());
	}

	/**
	 * Sends a CRITICAL_TICKET_BLOCKED notification to the owner of any King or
	 * Queen commit linked to this ticket.
	 */
	private void notifyCriticalTicketBlocked(WorkItem ticket) {
		List<WeeklyCommit> linkedCommits = commitRepo.findByWorkItemId(ticket.getId());
		for (WeeklyCommit commit : linkedCommits) {
			if (commit.getChessPiece() == ChessPiece.KING || commit.getChessPiece() == ChessPiece.QUEEN) {
				notificationService.createNotification(commit.getOwnerUserId(),
						NotificationEvent.CRITICAL_TICKET_BLOCKED, "Blocked ticket linked to " + commit.getChessPiece(),
						"Ticket \"" + ticket.getTitle() + "\" is now BLOCKED and is linked to your "
								+ commit.getChessPiece() + " commit \"" + commit.getTitle() + "\".",
						ticket.getId(), "TICKET");
			}
		}
	}

	// -------------------------------------------------------------------------
	// Status history
	// -------------------------------------------------------------------------

	@Transactional(readOnly = true)
	public List<TicketStatusHistoryResponse> getStatusHistory(UUID id) {
		requireTicket(id);
		return historyRepo.findByWorkItemIdOrderByCreatedAtAsc(id).stream().map(TicketStatusHistoryResponse::from)
				.toList();
	}

	// -------------------------------------------------------------------------
	// Delete
	// -------------------------------------------------------------------------

	public void deleteTicket(UUID id) {
		WorkItem item = requireTicket(id);
		workItemRepo.delete(item);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	WorkItem requireTicket(UUID id) {
		return workItemRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Ticket not found: " + id));
	}

	private WeeklyCommit requireCommit(UUID id) {
		return commitRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + id));
	}

	private WeeklyPlan requirePlan(UUID id) {
		return planRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + id));
	}

	private void transitionStatus(WorkItem item, TicketStatus newStatus, UUID changedByUserId) {
		TicketStatus currentStatus = item.getStatus();
		if (currentStatus == newStatus) {
			return;
		}

		Set<TicketStatus> allowed = ALLOWED_TRANSITIONS.getOrDefault(currentStatus, EnumSet.noneOf(TicketStatus.class));
		if (!allowed.contains(newStatus)) {
			throw new PlanValidationException(
					"Illegal ticket status transition: " + currentStatus + " → " + newStatus + ". Allowed: " + allowed);
		}

		WorkItemStatusHistory history = new WorkItemStatusHistory();
		history.setWorkItemId(item.getId());
		history.setFromStatus(currentStatus != null ? currentStatus.name() : null);
		history.setToStatus(newStatus.name());
		history.setChangedByUserId(changedByUserId);
		historyRepo.save(history);

		item.setStatus(newStatus);
	}

	/**
	 * Generates a unique key for a ticket within its team.
	 */
	private String generateKey(UUID teamId) {
		long count = workItemRepo.countByTeamId(teamId);
		return KEY_PREFIX + (count + 1);
	}

	private Specification<WorkItem> buildSpecification(TicketListParams params) {
		return Specification.where(equalsUuid("assigneeUserId", params.assigneeUserId()))
				.and(equalsUuid("teamId", params.teamId())).and(equalsUuid("rcdoNodeId", params.rcdoNodeId()))
				.and(equalsEnum("status", params.status())).and(equalsEnum("priority", params.priority()))
				.and(equalsValue("targetWeekStartDate", params.targetWeek()));
	}

	private static <T> Specification<WorkItem> equalsValue(String field, T value) {
		return (root, query, cb) -> value == null ? cb.conjunction() : cb.equal(root.get(field), value);
	}

	private static Specification<WorkItem> equalsUuid(String field, UUID value) {
		return equalsValue(field, value);
	}

	private static <T extends Enum<T>> Specification<WorkItem> equalsEnum(String field, T value) {
		return equalsValue(field, value);
	}

	private Sort buildSort(String sortBy, String sortDir) {
		Sort.Direction direction = "asc".equalsIgnoreCase(sortDir) ? Sort.Direction.ASC : Sort.Direction.DESC;
		String property = switch (sortBy) {
			case "key" -> "key";
			case "title" -> "title";
			case "status" -> "status";
			case "priority" -> "priority";
			case "updatedAt" -> "updatedAt";
			default -> "updatedAt";
		};
		return Sort.by(direction, property);
	}

	static void validateEstimatePoints(Integer points) {
		if (points != null && !VALID_ESTIMATE_POINTS.contains(points)) {
			throw new PlanValidationException("Estimate points must be one of {1, 2, 3, 5, 8}, got: " + points);
		}
	}
}

package com.weeklycommit.lock.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.service.RiskDetectionService;
import com.weeklycommit.audit.service.AuditLogService;
import com.weeklycommit.domain.entity.LockSnapshotCommit;
import com.weeklycommit.domain.entity.LockSnapshotHeader;
import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.NotificationEvent;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.LockSnapshotCommitRepository;
import com.weeklycommit.domain.repository.LockSnapshotHeaderRepository;
import com.weeklycommit.domain.repository.RcdoNodeRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.lock.dto.LockResponse;
import com.weeklycommit.lock.dto.LockSnapshotHeaderResponse;
import com.weeklycommit.lock.dto.ValidationError;
import com.weeklycommit.notification.service.NotificationService;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.dto.PlanResponse;
import com.weeklycommit.plan.dto.PlanWithCommitsResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.report.service.ReadModelRefreshService;
import java.time.Instant;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class LockService {

	private static final Logger log = LoggerFactory.getLogger(LockService.class);

	private static final int MAX_KING_PER_WEEK = 1;
	private static final int MAX_QUEEN_PER_WEEK = 2;
	private static final java.util.Set<Integer> VALID_ESTIMATE_POINTS = java.util.Set.of(1, 2, 3, 5, 8);

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final LockSnapshotHeaderRepository headerRepo;
	private final LockSnapshotCommitRepository commitSnapshotRepo;
	private final RcdoNodeRepository rcdoNodeRepo;
	private final ObjectMapper objectMapper;
	private final NotificationService notificationService;
	private final RiskDetectionService riskDetectionService;
	private final ReadModelRefreshService readModelRefreshService;
	private final AuditLogService auditLogService;

	public LockService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			LockSnapshotHeaderRepository headerRepo, LockSnapshotCommitRepository commitSnapshotRepo,
			RcdoNodeRepository rcdoNodeRepo, ObjectMapper objectMapper, NotificationService notificationService,
			RiskDetectionService riskDetectionService, ReadModelRefreshService readModelRefreshService,
			AuditLogService auditLogService) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.headerRepo = headerRepo;
		this.commitSnapshotRepo = commitSnapshotRepo;
		this.rcdoNodeRepo = rcdoNodeRepo;
		this.objectMapper = objectMapper;
		this.notificationService = notificationService;
		this.riskDetectionService = riskDetectionService;
		this.readModelRefreshService = readModelRefreshService;
		this.auditLogService = auditLogService;
	}

	// -------------------------------------------------------------------------
	// Manual lock
	// -------------------------------------------------------------------------

	/**
	 * Attempts to manually lock a DRAFT plan.
	 *
	 * <ul>
	 * <li>If the plan is already LOCKED the call is idempotent and returns
	 * success.</li>
	 * <li>If the plan is in any other non-DRAFT state a
	 * {@link PlanValidationException} is thrown (400).</li>
	 * <li>If hard validation fails the plan is <em>not</em> locked and the response
	 * contains the error list.</li>
	 * <li>On success the state transitions to LOCKED and a baseline snapshot is
	 * captured in the same transaction.</li>
	 * </ul>
	 */
	public LockResponse lockPlan(UUID planId, UUID actorUserId) {
		WeeklyPlan plan = findPlan(planId);

		if (plan.getState() == PlanState.LOCKED) {
			// Idempotent: already locked
			return LockResponse.success(buildPlanResponse(plan));
		}

		if (plan.getState() != PlanState.DRAFT) {
			throw new PlanValidationException("Plan " + planId + " cannot be locked from state " + plan.getState());
		}

		List<ValidationError> errors = validateForLock(plan);
		if (!errors.isEmpty()) {
			return LockResponse.validationFailed(errors);
		}

		// Compliance: on-time if locked before or at the deadline
		boolean onTime = !Instant.now().isAfter(plan.getLockDeadline());
		plan.setCompliant(onTime);
		plan.setState(PlanState.LOCKED);
		plan.setSystemLockedWithErrors(false);
		planRepo.save(plan);

		captureSnapshot(plan, false, List.of());
		triggerRiskDetection(plan.getId());
		triggerReadModelRefresh(plan.getId());

		auditLogService.record(AuditLogService.PLAN_LOCKED, actorUserId, "IC", AuditLogService.TARGET_PLAN, planId,
				null, Map.of("state", "LOCKED", "onTime", onTime));

		return LockResponse.success(buildPlanResponse(plan));
	}

	// -------------------------------------------------------------------------
	// Auto-lock (called by scheduled job, idempotent)
	// -------------------------------------------------------------------------

	/**
	 * Locks an expired DRAFT plan as a system action. If the plan has validation
	 * errors the lock still proceeds but {@code system_locked_with_errors} is set.
	 *
	 * <p>
	 * After locking, an {@code AUTO_LOCK_OCCURRED} notification is sent to the plan
	 * owner and a {@code MANAGER_EXCEPTION_DIGEST} notification is sent to the
	 * team's manager (if one exists).
	 */
	public void autoLockPlan(UUID planId) {
		WeeklyPlan plan = planRepo.findById(planId).orElse(null);
		if (plan == null || plan.getState() != PlanState.DRAFT) {
			return; // idempotent: nothing to do
		}

		List<ValidationError> errors = validateForLock(plan);

		plan.setState(PlanState.LOCKED);
		plan.setCompliant(false); // auto-lock is never manually compliant
		plan.setSystemLockedWithErrors(!errors.isEmpty());
		planRepo.save(plan);

		captureSnapshot(plan, true, errors);
		triggerRiskDetection(plan.getId());
		triggerReadModelRefresh(plan.getId());

		auditLogService.recordSystem(AuditLogService.PLAN_AUTO_LOCKED, AuditLogService.TARGET_PLAN, planId, null,
				Map.of("state", "LOCKED", "systemLockedWithErrors", !errors.isEmpty(), "ownerUserId",
						plan.getOwnerUserId().toString()));

		// Notification hooks — fire-and-forget: failures must not roll back the lock
		try {
			notificationService.createNotification(plan.getOwnerUserId(), NotificationEvent.AUTO_LOCK_OCCURRED,
					"Plan auto-locked",
					"Your weekly plan for " + plan.getWeekStartDate() + " was automatically locked by the system.",
					plan.getId(), "PLAN");

			notificationService.findManagerForTeam(plan.getTeamId())
					.ifPresent(
							managerId -> notificationService.createNotification(managerId,
									NotificationEvent.MANAGER_EXCEPTION_DIGEST, "Auto-lock on team plan",
									"A plan for week " + plan.getWeekStartDate() + " in your team was auto-locked"
											+ (errors.isEmpty() ? "." : " with validation errors."),
									plan.getId(), "PLAN"));
		} catch (Exception ex) {
			log.warn("Failed to send auto-lock notifications for plan {}: {}", planId, ex.getMessage());
		}
	}

	// -------------------------------------------------------------------------
	// Snapshot retrieval
	// -------------------------------------------------------------------------

	@Transactional(readOnly = true)
	public LockSnapshotHeaderResponse getLockSnapshot(UUID planId) {
		LockSnapshotHeader header = headerRepo.findByPlanId(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Lock snapshot not found for plan: " + planId));
		return LockSnapshotHeaderResponse.from(header);
	}

	// -------------------------------------------------------------------------
	// Hard validation
	// -------------------------------------------------------------------------

	/** Returns the list of hard-validation errors. Empty means valid. */
	List<ValidationError> validateForLock(WeeklyPlan plan) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());

		List<ValidationError> errors = new ArrayList<>();

		if (commits.isEmpty()) {
			errors.add(ValidationError.of("commits", "At least one commit is required to lock the plan"));
			return errors; // no point validating individual commits
		}

		int kingCount = 0;
		int queenCount = 0;

		for (WeeklyCommit commit : commits) {
			String prefix = "commit[" + commit.getId() + "]";

			if (commit.getTitle() == null || commit.getTitle().isBlank()) {
				errors.add(ValidationError.of(prefix + ".title", "Title is required"));
			}
			if (commit.getChessPiece() == null) {
				errors.add(ValidationError.of(prefix + ".chessPiece", "Chess piece is required"));
				continue; // skip piece-dependent checks
			}
			if (commit.getPriorityOrder() < 1) {
				errors.add(ValidationError.of(prefix + ".priorityOrder", "Priority order must be ≥ 1"));
			}
			if (commit.getRcdoNodeId() == null) {
				errors.add(ValidationError.of(prefix + ".rcdoNodeId", "Primary RCDO link is required at lock time"));
			}
			if (commit.getEstimatePoints() == null) {
				errors.add(ValidationError.of(prefix + ".estimatePoints", "Estimate points are required at lock time"));
			} else if (!VALID_ESTIMATE_POINTS.contains(commit.getEstimatePoints())) {
				errors.add(ValidationError.of(prefix + ".estimatePoints",
						"Estimate points must be one of {1, 2, 3, 5, 8}"));
			}
			if ((commit.getChessPiece() == ChessPiece.KING || commit.getChessPiece() == ChessPiece.QUEEN)
					&& (commit.getSuccessCriteria() == null || commit.getSuccessCriteria().isBlank())) {
				errors.add(ValidationError.of(prefix + ".successCriteria",
						"Success criteria required for " + commit.getChessPiece() + " commits"));
			}
			if (commit.getChessPiece() == ChessPiece.KING)
				kingCount++;
			if (commit.getChessPiece() == ChessPiece.QUEEN)
				queenCount++;
		}

		if (kingCount > MAX_KING_PER_WEEK) {
			errors.add(ValidationError.of("commits.king", "Maximum 1 King commit per week; found " + kingCount));
		}
		if (queenCount > MAX_QUEEN_PER_WEEK) {
			errors.add(ValidationError.of("commits.queen", "Maximum 2 Queen commits per week; found " + queenCount));
		}

		return errors;
	}

	// -------------------------------------------------------------------------
	// Snapshot creation (called within existing transaction)
	// -------------------------------------------------------------------------

	private void triggerRiskDetection(UUID planId) {
		try {
			riskDetectionService.detectAndStoreRiskSignalsById(planId);
		} catch (Exception ex) {
			log.warn("Failed to compute risk signals for plan {}: {}", planId, ex.getMessage());
		}
	}

	private void triggerReadModelRefresh(UUID planId) {
		try {
			readModelRefreshService.refreshForPlan(planId);
		} catch (Exception ex) {
			log.warn("Failed to refresh read models for plan {}: {}", planId, ex.getMessage());
		}
	}

	/**
	 * Creates an immutable lock snapshot. Throws if a snapshot already exists for
	 * this plan (write-once enforcement).
	 */
	private void captureSnapshot(WeeklyPlan plan, boolean bySystem, List<ValidationError> validationErrors) {
		// Immutability guard: snapshot is write-once per plan
		if (headerRepo.findByPlanId(plan.getId()).isPresent()) {
			throw new PlanValidationException(
					"Lock snapshot already exists for plan " + plan.getId() + " — snapshots are immutable");
		}

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());

		String payload = buildSnapshotPayload(plan, commits, validationErrors);

		LockSnapshotHeader header = new LockSnapshotHeader();
		header.setPlanId(plan.getId());
		header.setLockedBySystem(bySystem);
		header.setSnapshotPayload(payload);
		LockSnapshotHeader saved = headerRepo.save(header);

		for (WeeklyCommit commit : commits) {
			LockSnapshotCommit sc = new LockSnapshotCommit();
			sc.setSnapshotId(saved.getId());
			sc.setCommitId(commit.getId());
			sc.setSnapshotData(buildCommitSnapshot(commit));
			commitSnapshotRepo.save(sc);
		}

		// Back-reference on plan
		plan.setLockSnapshotId(saved.getId());
		planRepo.save(plan);
	}

	// -------------------------------------------------------------------------
	// JSON snapshot builders
	// -------------------------------------------------------------------------

	private String buildSnapshotPayload(WeeklyPlan plan, List<WeeklyCommit> commits,
			List<ValidationError> validationErrors) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("planId", str(plan.getId()));
		m.put("ownerUserId", str(plan.getOwnerUserId()));
		m.put("teamId", str(plan.getTeamId()));
		m.put("weekStartDate", plan.getWeekStartDate().toString());
		m.put("capacityBudgetPoints", plan.getCapacityBudgetPoints());
		m.put("lockedAt", Instant.now().toString());
		m.put("commits", commits.stream().map(this::buildCommitSnapshotMap).toList());
		if (!validationErrors.isEmpty()) {
			m.put("validationErrors", validationErrors);
		}
		return toJson(m);
	}

	private String buildCommitSnapshot(WeeklyCommit commit) {
		return toJson(buildCommitSnapshotMap(commit));
	}

	private Map<String, Object> buildCommitSnapshotMap(WeeklyCommit commit) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("id", str(commit.getId()));
		m.put("title", commit.getTitle());
		m.put("chessPiece", commit.getChessPiece() != null ? commit.getChessPiece().name() : null);
		m.put("priorityOrder", commit.getPriorityOrder());
		m.put("estimatePoints", commit.getEstimatePoints());
		m.put("successCriteria", commit.getSuccessCriteria());
		m.put("description", commit.getDescription());
		m.put("rcdoNodeId", str(commit.getRcdoNodeId()));
		m.put("workItemId", str(commit.getWorkItemId()));
		m.put("rcdoPath", buildRcdoPath(commit.getRcdoNodeId()));
		return m;
	}

	private List<Map<String, Object>> buildRcdoPath(UUID nodeId) {
		if (nodeId == null)
			return List.of();
		List<Map<String, Object>> path = new ArrayList<>();
		UUID current = nodeId;
		while (current != null) {
			RcdoNode node = rcdoNodeRepo.findById(current).orElse(null);
			if (node == null)
				break;
			Map<String, Object> entry = new LinkedHashMap<>();
			entry.put("id", str(node.getId()));
			entry.put("nodeType", node.getNodeType().name());
			entry.put("title", node.getTitle());
			entry.put("status", node.getStatus().name());
			path.add(0, entry); // root first
			current = node.getParentId();
		}
		return path;
	}

	// -------------------------------------------------------------------------
	// Helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan findPlan(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	private PlanWithCommitsResponse buildPlanResponse(WeeklyPlan plan) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());
		int total = commits.stream().mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0).sum();
		return new PlanWithCommitsResponse(PlanResponse.from(plan), commits.stream().map(CommitResponse::from).toList(),
				total);
	}

	private String toJson(Object obj) {
		try {
			return objectMapper.writeValueAsString(obj);
		} catch (JsonProcessingException e) {
			throw new IllegalStateException("Failed to serialize snapshot payload", e);
		}
	}

	private static String str(UUID id) {
		return id != null ? id.toString() : null;
	}
}

