import com.weeklycommit.reconcile.dto.ScopeChangeEventResponse;
import java.time.Instant;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import java.util.UUID;
import java.util.stream.Collectors;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Manages the RECONCILING phase of a weekly plan's lifecycle.
 *
 * <p>
 * Responsibilities:
 * <ol>
 * <li>Opening reconciliation — idempotent LOCKED → RECONCILING transition with
 * auto-achieve for linked DONE tickets.</li>
 * <li>Providing the reconciliation view — baseline vs current commit data.</li>
 * <li>Setting individual commit outcomes.</li>
 * <li>Submitting the final reconciliation — validates completeness, writes
 * immutable snapshot, and transitions to RECONCILED.</li>
 * </ol>
 */
@Service
@Transactional
public class ReconciliationService {

	private static final Logger log = LoggerFactory.getLogger(ReconciliationService.class);

	/** Outcomes that require accompanying notes. */
	private static final Set<CommitOutcome> NOTES_REQUIRED_OUTCOMES = Set.of(CommitOutcome.PARTIALLY_ACHIEVED,
			CommitOutcome.NOT_ACHIEVED, CommitOutcome.CANCELED);

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final WorkItemRepository workItemRepo;
	private final ScopeChangeEventRepository eventRepo;
	private final LockSnapshotHeaderRepository lockHeaderRepo;
	private final LockSnapshotCommitRepository lockCommitRepo;
	private final ReconcileSnapshotHeaderRepository reconcileHeaderRepo;
	private final ReconcileSnapshotCommitRepository reconcileCommitRepo;
	private final ObjectMapper objectMapper;
	private final NotificationService notificationService;
	private final ReadModelRefreshService readModelRefreshService;
	private final AuditLogService auditLogService;

	public ReconciliationService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			WorkItemRepository workItemRepo, ScopeChangeEventRepository eventRepo,
			LockSnapshotHeaderRepository lockHeaderRepo, LockSnapshotCommitRepository lockCommitRepo,
			ReconcileSnapshotHeaderRepository reconcileHeaderRepo,
			ReconcileSnapshotCommitRepository reconcileCommitRepo, ObjectMapper objectMapper,
			NotificationService notificationService, ReadModelRefreshService readModelRefreshService,
			AuditLogService auditLogService) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.workItemRepo = workItemRepo;
		this.eventRepo = eventRepo;
		this.lockHeaderRepo = lockHeaderRepo;
		this.lockCommitRepo = lockCommitRepo;
		this.reconcileHeaderRepo = reconcileHeaderRepo;
		this.reconcileCommitRepo = reconcileCommitRepo;
		this.objectMapper = objectMapper;
		this.notificationService = notificationService;
		this.readModelRefreshService = readModelRefreshService;
		this.auditLogService = auditLogService;
	}

	// -------------------------------------------------------------------------
	// Open reconciliation (LOCKED → RECONCILING)
	// -------------------------------------------------------------------------

	/**
	 * Transitions a LOCKED plan to RECONCILING. Idempotent: if already RECONCILING
	 * the call is a no-op.
	 *
	 * <p>
	 * Side-effect: any commit whose linked work-item has status DONE is
	 * automatically given an ACHIEVED outcome.
	 *
	 * @throws PlanValidationException
	 *             if the plan is not LOCKED or RECONCILING.
	 */
	public void openReconciliation(UUID planId) {
		WeeklyPlan plan = requirePlan(planId);

		if (plan.getState() == PlanState.RECONCILING) {
			return; // idempotent
		}

		if (plan.getState() != PlanState.LOCKED) {
			throw new PlanValidationException(
					"Reconciliation can only be opened for LOCKED plans; current state: " + plan.getState());
		}

		plan.setState(PlanState.RECONCILING);
		planRepo.save(plan);

		autoAchieveDoneTickets(plan.getId());

		auditLogService.recordSystem(AuditLogService.RECONCILE_OPENED, AuditLogService.TARGET_PLAN, planId, null,
				Map.of("state", "RECONCILING", "ownerUserId", plan.getOwnerUserId().toString()));

		// Notify plan owner that reconciliation has been opened
		try {
			notificationService.createNotification(plan.getOwnerUserId(), NotificationEvent.RECONCILIATION_OPENED,
					"Reconciliation opened",
					"Reconciliation has been opened for your weekly plan for " + plan.getWeekStartDate() + ".",
					plan.getId(), "PLAN");
		} catch (Exception ex) {
			log.warn("Failed to send reconciliation-opened notification for plan {}: {}", planId, ex.getMessage());
		}
	}

	// -------------------------------------------------------------------------
	// Reconciliation view
	// -------------------------------------------------------------------------

	/**
	 * Builds the full reconciliation dashboard for a RECONCILING (or RECONCILED)
	 * plan.
	 */
	@Transactional(readOnly = true)
	public ReconciliationViewResponse getReconciliationView(UUID planId) {
		WeeklyPlan plan = requirePlan(planId);
		if (plan.getState() != PlanState.RECONCILING && plan.getState() != PlanState.RECONCILED) {
			throw new PlanValidationException(
					"Reconciliation view is only available for plans in RECONCILING or RECONCILED state; "
							+ "current state: " + plan.getState());
		}

		// Baseline data
		LockSnapshotHeader lockHeader = lockHeaderRepo.findByPlanId(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Lock snapshot not found for plan: " + planId));
		List<LockSnapshotCommit> lockCommits = lockCommitRepo.findBySnapshotId(lockHeader.getId());
		Map<UUID, Map<String, Object>> baselineByCommitId = buildBaselineMap(lockCommits);
		int baselineTotalPoints = baselineByCommitId.values().stream()
				.mapToInt(m -> m.get("estimatePoints") instanceof Number n ? n.intValue() : 0).sum();

		// Current commits
		List<WeeklyCommit> currentCommits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);

		// Scope-change events, grouped by commit
		List<ScopeChangeEvent> allEvents = eventRepo.findByPlanIdOrderByCreatedAtAsc(planId);
		Map<UUID, List<ScopeChangeEvent>> eventsByCommit = allEvents.stream().filter(e -> e.getCommitId() != null)
				.collect(Collectors.groupingBy(ScopeChangeEvent::getCommitId));

		// Identify commits added or removed post-lock
		Set<UUID> addedPostLock = allEvents.stream()
				.filter(e -> e.getCategory() == ScopeChangeCategory.COMMIT_ADDED && e.getCommitId() != null)
				.map(ScopeChangeEvent::getCommitId).collect(Collectors.toSet());
		Set<UUID> removedPostLock = allEvents.stream()
				.filter(e -> e.getCategory() == ScopeChangeCategory.COMMIT_REMOVED && e.getCommitId() != null)
				.map(ScopeChangeEvent::getCommitId).collect(Collectors.toSet());

		List<ReconcileCommitView> views = new ArrayList<>();
		int currentTotalPoints = 0;
		int outcomesSetCount = 0;

		for (WeeklyCommit commit : currentCommits) {
			int pts = commit.getEstimatePoints() != null ? commit.getEstimatePoints() : 0;
			if (commit.getOutcome() != CommitOutcome.CANCELED) {
				currentTotalPoints += pts;
			}
			if (commit.getOutcome() != null) {
				outcomesSetCount++;
			}

			List<ScopeChangeEventResponse> commitEvents = eventsByCommit.getOrDefault(commit.getId(), List.of())
					.stream().map(ScopeChangeEventResponse::from).toList();

			String ticketStatus = null;
			if (commit.getWorkItemId() != null) {
				ticketStatus = workItemRepo.findById(commit.getWorkItemId()).map(wi -> wi.getStatus().name())
						.orElse(null);
			}

			Map<String, Object> baseline = baselineByCommitId.get(commit.getId());

			views.add(new ReconcileCommitView(commit.getId(), commit.getTitle(), commit.getChessPiece(),
					commit.getEstimatePoints(), commit.getOutcome(), commit.getOutcomeNotes(), baseline, commitEvents,
					ticketStatus, addedPostLock.contains(commit.getId()), removedPostLock.contains(commit.getId())));
		}

		return new ReconciliationViewResponse(PlanResponse.from(plan), views, baselineTotalPoints, currentTotalPoints,
				currentCommits.size(), outcomesSetCount);
	}

	// -------------------------------------------------------------------------
	// Set commit outcome
	// -------------------------------------------------------------------------

	/**
	 * Sets (or updates) the outcome on a commit during RECONCILING.
	 *
	 * @throws PlanValidationException
	 *             if notes are required but absent.
	 */
	public CommitResponse setCommitOutcome(UUID planId, UUID commitId, CommitOutcome outcome, String notes) {
		WeeklyPlan plan = requirePlan(planId);
		if (plan.getState() != PlanState.RECONCILING) {
			throw new PlanValidationException(
					"Outcomes can only be set while the plan is in RECONCILING state; current state: "
							+ plan.getState());
		}

		WeeklyCommit commit = requireCommit(commitId);
		if (!commit.getPlanId().equals(planId)) {
			throw new PlanValidationException("Commit " + commitId + " does not belong to plan " + planId);
		}

		// Notes required for PARTIALLY_ACHIEVED, NOT_ACHIEVED, CANCELED
		if (NOTES_REQUIRED_OUTCOMES.contains(outcome) && (notes == null || notes.isBlank())) {
			throw new PlanValidationException("Outcome notes are required for outcome " + outcome);
		}

		String prevOutcome = commit.getOutcome() != null ? commit.getOutcome().name() : null;
		commit.setOutcome(outcome);
		commit.setOutcomeNotes(notes);
		commitRepo.save(commit);

		auditLogService.record(AuditLogService.COMMIT_OUTCOME_SET, plan.getOwnerUserId(), "IC",
				AuditLogService.TARGET_COMMIT, commitId, prevOutcome != null ? Map.of("outcome", prevOutcome) : null,
				Map.of("outcome", outcome.name(), "notes", notes != null ? notes : ""));

		return CommitResponse.from(commit);
	}

	// -------------------------------------------------------------------------
	// Submit reconciliation
	// -------------------------------------------------------------------------

	/**
	 * Validates that all commits have outcomes, then writes the immutable
	 * reconciliation snapshot and transitions the plan to RECONCILED.
	 *
	 * @throws PlanValidationException
	 *             if any commit still has no outcome.
	 */
	public ReconciliationViewResponse submitReconciliation(UUID planId) {
		WeeklyPlan plan = requirePlan(planId);
		if (plan.getState() != PlanState.RECONCILING) {
			throw new PlanValidationException(
					"Reconciliation can only be submitted from RECONCILING state; current state: " + plan.getState());
		}

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);

		// Validate every commit has an outcome
		List<UUID> missing = commits.stream().filter(c -> c.getOutcome() == null).map(WeeklyCommit::getId).toList();
		if (!missing.isEmpty()) {
			throw new PlanValidationException(
					"All commits must have an outcome before reconciliation can be submitted. "
							+ "Commits without outcomes: " + missing);
		}

		// Compute compliance: plan was already marked compliant/non-compliant at lock
		// time; we keep that flag and add an additional "all achieved" flag via the
		// snapshot payload.
		boolean allAchieved = commits.stream()
				.allMatch(c -> c.getOutcome() == CommitOutcome.ACHIEVED || c.getOutcome() == CommitOutcome.CANCELED);

		// Immutability guard: reconcile snapshot is write-once per plan
		if (reconcileHeaderRepo.findByPlanId(planId).isPresent()) {
			throw new PlanValidationException(
					"Reconcile snapshot already exists for plan " + planId + " — snapshots are immutable");
		}

		// Write immutable reconcile snapshot
		ReconcileSnapshotHeader header = new ReconcileSnapshotHeader();
		header.setPlanId(planId);
		header.setSnapshotPayload(buildReconcilePayload(plan, commits, allAchieved));
		ReconcileSnapshotHeader savedHeader = reconcileHeaderRepo.save(header);

		for (WeeklyCommit commit : commits) {
			ReconcileSnapshotCommit sc = new ReconcileSnapshotCommit();
			sc.setSnapshotId(savedHeader.getId());
			sc.setCommitId(commit.getId());
			sc.setOutcome(commit.getOutcome());
			sc.setSnapshotData(buildCommitSnapshot(commit));
			reconcileCommitRepo.save(sc);
		}

		// Transition to RECONCILED
		plan.setReconcileSnapshotId(savedHeader.getId());
		plan.setState(PlanState.RECONCILED);
		plan.setCompliant(plan.isCompliant() && allAchieved);
		planRepo.save(plan);

		triggerReadModelRefresh(planId);

		auditLogService.record(AuditLogService.RECONCILE_SUBMITTED, plan.getOwnerUserId(), "IC",
				AuditLogService.TARGET_PLAN, planId, null, Map.of("state", "RECONCILED", "allAchieved", allAchieved));

		return getReconciliationView(planId);
	}

	// -------------------------------------------------------------------------
	// Auto-achieve helper (called by openReconciliation)
	// -------------------------------------------------------------------------

	private void autoAchieveDoneTickets(UUID planId) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		for (WeeklyCommit commit : commits) {
			if (commit.getWorkItemId() != null && commit.getOutcome() == null) {
				Optional<WorkItem> wiOpt = workItemRepo.findById(commit.getWorkItemId());
				if (wiOpt.isPresent() && wiOpt.get().getStatus() == TicketStatus.DONE) {
					commit.setOutcome(CommitOutcome.ACHIEVED);
					commitRepo.save(commit);
				}
			}
		}
	}

	// -------------------------------------------------------------------------
	// Snapshot builders
	// -------------------------------------------------------------------------

	private String buildReconcilePayload(WeeklyPlan plan, List<WeeklyCommit> commits, boolean allAchieved) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("planId", plan.getId().toString());
		m.put("ownerUserId", plan.getOwnerUserId().toString());
		m.put("teamId", plan.getTeamId().toString());
		m.put("weekStartDate", plan.getWeekStartDate().toString());
		m.put("reconciledAt", Instant.now().toString());
		m.put("allAchieved", allAchieved);
		m.put("commits", commits.stream().map(this::commitToMapForSnapshot).toList());
		return toJson(m);
	}

	private String buildCommitSnapshot(WeeklyCommit commit) {
		return toJson(commitToMapForSnapshot(commit));
	}

	private Map<String, Object> commitToMapForSnapshot(WeeklyCommit commit) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("id", commit.getId().toString());
		m.put("title", commit.getTitle());
		m.put("chessPiece", commit.getChessPiece() != null ? commit.getChessPiece().name() : null);
		m.put("priorityOrder", commit.getPriorityOrder());
		m.put("estimatePoints", commit.getEstimatePoints());
		m.put("successCriteria", commit.getSuccessCriteria());
		m.put("outcome", commit.getOutcome() != null ? commit.getOutcome().name() : null);
		m.put("outcomeNotes", commit.getOutcomeNotes());
		m.put("rcdoNodeId", commit.getRcdoNodeId() != null ? commit.getRcdoNodeId().toString() : null);
		m.put("workItemId", commit.getWorkItemId() != null ? commit.getWorkItemId().toString() : null);
		return m;
	}

	// -------------------------------------------------------------------------
	// Baseline map builder
	// -------------------------------------------------------------------------

	private Map<UUID, Map<String, Object>> buildBaselineMap(List<LockSnapshotCommit> lockCommits) {
		Map<UUID, Map<String, Object>> result = new HashMap<>();
		for (LockSnapshotCommit lsc : lockCommits) {
			try {
				JsonNode node = objectMapper.readTree(lsc.getSnapshotData());
				Map<String, Object> m = new LinkedHashMap<>();
				node.fields().forEachRemaining(entry -> m.put(entry.getKey(), nodeToValue(entry.getValue())));
				result.put(lsc.getCommitId(), m);
			} catch (JsonProcessingException e) {
				// return empty map for this commit if JSON is malformed
				result.put(lsc.getCommitId(), Map.of());
			}
		}
		return result;
	}

	private Object nodeToValue(JsonNode node) {
		if (node.isNull())
			return null;
		if (node.isInt())
			return node.intValue();
		if (node.isLong())
			return node.longValue();
		if (node.isBoolean())
			return node.booleanValue();
		if (node.isTextual())
			return node.textValue();
		return node.toString();
	}

	// -------------------------------------------------------------------------
	// Helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan requirePlan(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private String toJson(Object o) {
		try {
			return objectMapper.writeValueAsString(o);
		} catch (JsonProcessingException e) {
			throw new IllegalStateException("JSON serialisation failed", e);
		}
	}

	private void triggerReadModelRefresh(UUID planId) {
		try {
			readModelRefreshService.refreshForPlan(planId);
		} catch (Exception ex) {
			log.warn("Failed to refresh read models for plan {}: {}", planId, ex.getMessage());
		}
	}
}

package com.weeklycommit.plan.service;

import com.weeklycommit.audit.service.AuditLogService;
import com.weeklycommit.config.service.ConfigurationService;
import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.UserAccountRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.dto.PlanResponse;
import com.weeklycommit.plan.dto.PlanWithCommitsResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.ZoneOffset;
import java.time.temporal.TemporalAdjusters;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Lazy;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Propagation;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class WeeklyPlanService {

	private final WeeklyPlanRepository planRepo;
	private final UserAccountRepository userRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ConfigurationService configurationService;
	private final AuditLogService auditLogService;

	/**
	 * Self-reference through the Spring proxy so that calls to
	 * {@link #createPlanInNewTransaction} acquire their own transaction even when
	 * invoked from within this bean. {@code @Lazy} breaks the circular-dependency
	 * cycle that would otherwise prevent startup.
	 */
	@Autowired
	@Lazy
	private WeeklyPlanService self;

	public WeeklyPlanService(WeeklyPlanRepository planRepo, UserAccountRepository userRepo,
			WeeklyCommitRepository commitRepo, ConfigurationService configurationService,
			AuditLogService auditLogService) {
		this.planRepo = planRepo;
		this.userRepo = userRepo;
		this.commitRepo = commitRepo;
		this.configurationService = configurationService;
		this.auditLogService = auditLogService;
	}

	// -------------------------------------------------------------------------
	// Public API
	// -------------------------------------------------------------------------

	/**
	 * Returns the existing plan for the given user+week, creating one if it does
	 * not yet exist. Safe under concurrent requests: if two requests race to create
	 * the same plan simultaneously (e.g. React 18 Strict Mode double-invocation),
	 * only one INSERT will succeed; the other catches the unique-constraint
	 * violation and falls back to a fresh SELECT.
	 *
	 * <p>Runs with {@code NOT_SUPPORTED} propagation so that the find and the
	 * create each use their own short-lived transactions (via {@link #self}) rather
	 * than sharing one transaction that would be rolled back on conflict.
	 */
	@Transactional(propagation = Propagation.NOT_SUPPORTED)
	public WeeklyPlan getOrCreatePlan(UUID userId, LocalDate weekStartDate) {
		// Fast-path: plan already exists — no write transaction needed.
		var existing = planRepo.findByOwnerUserIdAndWeekStartDate(userId, weekStartDate);
		if (existing.isPresent()) {
			return existing.get();
		}

		try {
			// Delegate to a REQUIRES_NEW method (via the Spring proxy) so the
			// INSERT commits independently before we continue.
			return self.createPlanInNewTransaction(userId, weekStartDate);
		} catch (DataIntegrityViolationException ex) {
			// A concurrent request won the race and already committed the plan.
			// Do a fresh SELECT — it is now visible in a new read.
			return planRepo.findByOwnerUserIdAndWeekStartDate(userId, weekStartDate)
					.orElseThrow(() -> new IllegalStateException(
							"Plan not found after duplicate-key violation for user=" + userId
									+ " week=" + weekStartDate, ex));
		}
	}

	/**
	 * Creates the draft plan in its own brand-new transaction so that the INSERT
	 * is committed (or rolled back on conflict) before the caller in
	 * {@link #getOrCreatePlan} sees the result.
	 *
	 * <p>Must be called through the Spring proxy (i.e. via {@link #self}) for the
	 * {@code REQUIRES_NEW} propagation to take effect.
	 */
	@Transactional(propagation = Propagation.REQUIRES_NEW)
	public WeeklyPlan createPlanInNewTransaction(UUID userId, LocalDate weekStartDate) {
		return createDraftPlan(userId, weekStartDate);
	}

	/**
	 * Convenience: resolve the current week's Monday and delegate to getOrCreate.
	 */
	public WeeklyPlan getMyCurrentWeekPlan(UUID userId) {
		return getOrCreatePlan(userId, currentWeekStart());
	}

	/** Returns the plan with its commits ordered by priority. */
	@Transactional(readOnly = true)
	public PlanWithCommitsResponse getPlanWithCommits(UUID planId) {
		WeeklyPlan plan = findById(planId);
		return toResponse(plan);
	}

	/** Lists all plans for a user in descending week order. */
	@Transactional(readOnly = true)
	public List<PlanResponse> listPlansForUser(UUID userId) {
		return planRepo.findByOwnerUserIdOrderByWeekStartDateDesc(userId).stream().map(PlanResponse::from).toList();
	}

	/** Calculates the Monday of the current ISO week (UTC). */
	public static LocalDate currentWeekStart() {
		return LocalDate.now(ZoneOffset.UTC).with(TemporalAdjusters.previousOrSame(DayOfWeek.MONDAY));
	}

	// -------------------------------------------------------------------------
	// Internal helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan createDraftPlan(UUID userId, LocalDate weekStartDate) {
		UserAccount user = userRepo.findById(userId)
				.orElseThrow(() -> new ResourceNotFoundException("User not found: " + userId));

		if (user.getHomeTeamId() == null) {
			throw new PlanValidationException("User " + userId + " has no home team; cannot create a weekly plan");
		}

		UUID teamId = user.getHomeTeamId();
		int budgetPoints = configurationService.getEffectiveCapacity(userId, weekStartDate).budgetPoints();

		WeeklyPlan plan = new WeeklyPlan();
		plan.setOwnerUserId(userId);
		plan.setTeamId(teamId);
		plan.setWeekStartDate(weekStartDate);
		plan.setState(PlanState.DRAFT);
		plan.setCapacityBudgetPoints(budgetPoints);

		// Derive per-team cadence deadlines from effective configuration
		plan.setLockDeadline(configurationService.computeLockDeadline(teamId, weekStartDate));
		plan.setReconcileDeadline(configurationService.computeReconcileDeadline(teamId, weekStartDate));

		WeeklyPlan saved = planRepo.save(plan);

		auditLogService.record(AuditLogService.PLAN_CREATED, userId, "IC", AuditLogService.TARGET_PLAN, saved.getId(),
				null, Map.of("ownerUserId", userId.toString(), "weekStartDate", weekStartDate.toString(), "teamId",
						teamId.toString()));

		return saved;
	}

	WeeklyPlan findById(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	PlanWithCommitsResponse toResponse(WeeklyPlan plan) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());
		int totalPoints = commits.stream().mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0)
				.sum();
		return new PlanWithCommitsResponse(PlanResponse.from(plan), commits.stream().map(CommitResponse::from).toList(),
				totalPoints);
	}
}

/**
 * AI API client functions for all AI-powered endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AiStatusResponse {
  aiEnabled: boolean;
  providerName: string;
  providerVersion: string;
  available: boolean;
}

export interface CommitDraftAssistRequest {
  userId: string;
  planId: string;
  commitId?: string;
  currentTitle: string;
  currentDescription?: string;
  currentSuccessCriteria?: string;
  currentEstimatePoints?: number;
  chessPiece?: string;
}

export interface CommitDraftAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  suggestedTitle?: string | null;
  suggestedDescription?: string | null;
  suggestedSuccessCriteria?: string | null;
  suggestedEstimatePoints?: number | null;
  rationale?: string;
}

export interface CommitLintRequest {
  userId: string;
  planId: string;
}

export interface LintMessage {
  code: string;
  message: string;
  commitId?: string;
}

export interface CommitLintResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  hardValidation: LintMessage[];
  softGuidance: LintMessage[];
  rationale?: string;
}

export interface RiskSignal {
  id: string;
  signalType: string;
  rationale: string;
  planId: string;
  commitId?: string | null;
  createdAt: string;
}

export interface PlanRiskSignalsResponse {
  aiAvailable: boolean;
  planId: string;
  signals: RiskSignal[];
}

export type FeedbackAction = "ACCEPTED" | "DISMISSED" | "EDITED";

export interface AiFeedbackRequest {
  suggestionId: string;
  userId: string;
  action: FeedbackAction;
  notes?: string;
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createAiApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /** GET /api/ai/status — provider health/availability check. */
    getStatus: (): Promise<AiStatusResponse> =>
      client.get("/ai/status"),

    /** POST /api/ai/commit-draft-assist — get draft improvement suggestions. */
    commitDraftAssist: (
      request: CommitDraftAssistRequest,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", request),

    /** POST /api/ai/commit-lint — run commit quality lint on a plan. */
    commitLint: (request: CommitLintRequest): Promise<CommitLintResponse> =>
      client.post("/ai/commit-lint", request),

    /** GET /api/plans/{id}/risk-signals — risk signals for a plan. */
    getRiskSignals: (planId: string): Promise<PlanRiskSignalsResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/risk-signals`, {
        headers: actorHeader,
      }),

    /** POST /api/ai/feedback — record thumbs up/down on a suggestion. */
    recordFeedback: (request: AiFeedbackRequest): Promise<void> =>
      client.post("/ai/feedback", request),
  };
}

export type AiApi = ReturnType<typeof createAiApi>;

/**
 * React hooks for AI API endpoints.
 */
import { useMemo } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createAiApi, type AiApi, type AiStatusResponse, type PlanRiskSignalsResponse } from "./aiApi.js";

/** Returns a stable AiApi instance bound to the current user's auth token. */
export function useAiApi(): AiApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createAiApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

/** Fetches the AI provider status. */
export function useAiStatus(): QueryState<AiStatusResponse> {
  const api = useAiApi();
  return useQuery<AiStatusResponse>("ai-status", () => api.getStatus());
}

/** Fetches risk signals for a specific plan. */
export function useRiskSignals(
  planId: string | null,
): QueryState<PlanRiskSignalsResponse> {
  const api = useAiApi();
  return useQuery<PlanRiskSignalsResponse>(
    `risk-signals-${planId ?? "none"}`,
    () => {
      if (!planId) return Promise.reject(new Error("No plan ID"));
      return api.getRiskSignals(planId);
    },
    { enabled: planId != null },
  );
}

/**
 * Thumbs up / thumbs down feedback buttons for AI suggestions.
 * Records feedback via POST /api/ai/feedback.
 */
import { useState, useCallback } from "react";
import { ThumbsUp, ThumbsDown } from "lucide-react";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import { useAiApi } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { FeedbackAction } from "../../api/aiApi.js";

interface AiFeedbackButtonsProps {
  suggestionId: string;
  className?: string;
}

export function AiFeedbackButtons({ suggestionId, className }: AiFeedbackButtonsProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const [submitted, setSubmitted] = useState<FeedbackAction | null>(null);

  const handleFeedback = useCallback(
    async (action: FeedbackAction) => {
      try {
        await aiApi.recordFeedback({ suggestionId, userId, action });
        setSubmitted(action);
      } catch {
        // Non-critical — don't block the UI
      }
    },
    [aiApi, suggestionId, userId],
  );

  if (submitted) {
    return (
      <span className={cn("text-xs text-muted italic", className)}>
        {submitted === "ACCEPTED" ? "Thanks! 👍" : "Noted 👎"}
      </span>
    );
  }

  return (
    <span className={cn("inline-flex gap-1", className)}>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("ACCEPTED")}
        aria-label="Helpful suggestion"
        className="h-6 w-6 text-muted hover:text-success"
        data-testid="ai-feedback-accept"
      >
        <ThumbsUp className="h-3.5 w-3.5" />
      </Button>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("DISMISSED")}
        aria-label="Not helpful"
        className="h-6 w-6 text-muted hover:text-danger"
        data-testid="ai-feedback-dismiss"
      >
        <ThumbsDown className="h-3.5 w-3.5" />
      </Button>
    </span>
  );
}

/**
 * AI commit lint panel — replaces the placeholder in PreLockValidationPanel.
 * Calls POST /api/ai/commit-lint and displays hard + soft lint messages
 * with feedback buttons on each.
 */
import { useState, useCallback } from "react";
import { Bot, RefreshCw } from "lucide-react";
import { Button } from "../ui/Button.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import type { CommitLintResponse } from "../../api/aiApi.js";

interface AiLintPanelProps {
  planId: string;
  userId: string;
}

export function AiLintPanel({ planId, userId }: AiLintPanelProps) {
  const aiApi = useAiApi();
  const { data: status } = useAiStatus();
  const [lintResult, setLintResult] = useState<CommitLintResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const runLint = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await aiApi.commitLint({ userId, planId });
      setLintResult(result);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Lint failed");
    } finally {
      setLoading(false);
    }
  }, [aiApi, planId, userId]);

  // AI not available — show disabled state
  if (status && !status.available) {
    return (
      <div className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI commit quality hints unavailable ({status.providerName})
      </div>
    );
  }

  // Not yet run
  if (!lintResult && !loading) {
    return (
      <div className="flex items-center gap-2" data-testid="ai-lint-ready">
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-7 text-xs border border-dashed border-border" data-testid="ai-lint-run-btn">
          <Bot className="h-3.5 w-3.5" />
          Run AI Quality Check
        </Button>
      </div>
    );
  }

  // Loading
  if (loading) {
    return (
      <div className="flex items-center gap-2 text-xs text-muted animate-pulse" data-testid="ai-lint-loading">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        Analyzing commit quality…
      </div>
    );
  }

  // Error
  if (error) {
    return (
      <div className="flex items-center gap-2 text-xs text-danger" data-testid="ai-lint-error">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        {error}
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs">
          <RefreshCw className="h-3 w-3" />Retry
        </Button>
      </div>
    );
  }

  // Results
  if (!lintResult?.aiAvailable) {
    return (
      <div className="text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 inline mr-1" />AI lint unavailable
      </div>
    );
  }

  const hasHard = lintResult.hardValidation.length > 0;
  const hasSoft = lintResult.softGuidance.length > 0;

  return (
    <div className="flex flex-col gap-2" data-testid="ai-lint-results">
      {/* Header with refresh */}
      <div className="flex items-center justify-between">
        <span className="flex items-center gap-1.5 text-xs font-semibold text-muted">
          <Bot className="h-3.5 w-3.5" />AI Quality Check
        </span>
        <div className="flex items-center gap-1.5">
          {lintResult.suggestionId && <AiFeedbackButtons suggestionId={lintResult.suggestionId} />}
          <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs" data-testid="ai-lint-refresh">
            <RefreshCw className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Hard validations */}
      {hasHard && (
        <div className="rounded-sm border border-red-200 bg-red-50 px-3 py-2" data-testid="ai-lint-hard">
          <p className="m-0 mb-1 text-xs font-semibold text-red-800">Hard Issues</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.hardValidation.map((msg, i) => (
              <li key={i} className="text-xs text-red-700">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Soft guidance */}
      {hasSoft && (
        <div className="rounded-sm border border-amber-200 bg-amber-50 px-3 py-2" data-testid="ai-lint-soft">
          <p className="m-0 mb-1 text-xs font-semibold text-amber-800">Suggestions</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.softGuidance.map((msg, i) => (
              <li key={i} className="text-xs text-amber-700">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* All clear */}
      {!hasHard && !hasSoft && (
        <div className="text-xs text-success flex items-center gap-1" data-testid="ai-lint-clear">
          ✓ No quality issues detected
        </div>
      )}
    </div>
  );
}

/**
 * My Week — personal weekly plan view.
 * Route: /weekly/my-week
 */
import { useState, useCallback, useMemo } from "react";
import { ChevronLeft, ChevronRight, Lock, AlertTriangle, Check, X } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Badge } from "../components/ui/Badge.js";
import { Card, CardHeader, CardTitle, CardContent } from "../components/ui/Card.js";
import { Dialog, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "../components/ui/Dialog.js";
import { useCurrentPlan, usePlanApi } from "../api/planHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { usePlanHistory, useCarryForwardLineage, useTicketApi } from "../api/ticketHooks.js";
import { PlanHistoryView } from "../components/myweek/PlanHistoryView.js";
import { CarryForwardLineageView } from "../components/myweek/CarryForwardLineageView.js";
import { TicketForm } from "../components/tickets/TicketForm.js";
import { useHostBridge } from "../host/HostProvider.js";
import type { CreateTicketPayload } from "../api/ticketTypes.js";
import { CommitList } from "../components/myweek/CommitList.js";
import { CommitForm } from "../components/myweek/CommitForm.js";
import { CapacityMeter } from "../components/myweek/CapacityMeter.js";
import { SoftWarningsPanel } from "../components/myweek/SoftWarningsPanel.js";
import { PreLockValidationPanel } from "../components/lock/PreLockValidationPanel.js";
import { LockConfirmDialog } from "../components/lock/LockConfirmDialog.js";
import { ScopeChangeDialog } from "../components/lock/ScopeChangeDialog.js";
import { ScopeChangeTimeline } from "../components/lock/ScopeChangeTimeline.js";
import { getEffectivePreLockErrors } from "../components/lock/lockValidation.js";
import type {
  CommitResponse, PlanState, LockValidationError,
  ScopeChangeEventResponse, UpdateCommitPayload, CreateCommitPayload,
} from "../api/planTypes.js";

// ── Helpers ────────────────────────────────────────────────────────────────

function getWeekStartDate(offsetWeeks = 0): string {
  const now = new Date();
  const dayOfWeek = now.getDay();
  const daysToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  const monday = new Date(now);
  monday.setDate(now.getDate() + daysToMonday + offsetWeeks * 7);
  return monday.toISOString().slice(0, 10);
}

function formatWeekLabel(isoDate: string): string {
  const d = new Date(`${isoDate}T00:00:00`);
  return `Week of ${d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}`;
}

// ── PlanStateBadge ──────────────────────────────────────────────────────────

const STATE_VARIANT: Record<PlanState, "draft" | "locked" | "reconciling" | "reconciled"> = {
  DRAFT: "draft", LOCKED: "locked", RECONCILING: "reconciling", RECONCILED: "reconciled",
};

function PlanStateBadge({ state }: { readonly state: PlanState }) {
  return <Badge data-testid="plan-state-badge" variant={STATE_VARIANT[state]}>{state}</Badge>;
}

// ── ComplianceBadge ─────────────────────────────────────────────────────────

function ComplianceBadge({ compliant }: { readonly compliant: boolean }) {
  return compliant ? (
    <span data-testid="compliance-badge-ok" title="Plan meets all lock requirements" className="flex items-center gap-1 text-sm font-medium text-success">
      <Check className="h-3.5 w-3.5" aria-hidden="true" />Compliant
    </span>
  ) : (
    <span data-testid="compliance-badge-warn" title="Plan has unresolved compliance issues" className="flex items-center gap-1 text-sm font-medium text-warning">
      <AlertTriangle className="h-3.5 w-3.5" aria-hidden="true" />Not compliant
    </span>
  );
}

// ── DeleteConfirmDialog ─────────────────────────────────────────────────────

function DeleteConfirmDialog({ title, onConfirm, onCancel }: { readonly title: string; readonly onConfirm: () => void; readonly onCancel: () => void }) {
  return (
    <Dialog open onClose={onCancel} aria-label="Delete commit" data-testid="delete-confirm-dialog">
      <DialogHeader>
        <DialogTitle>Delete commit?</DialogTitle>
        <DialogDescription>
          Are you sure you want to delete <strong>"{title}"</strong>? This cannot be undone.
        </DialogDescription>
      </DialogHeader>
      <DialogFooter>
        <Button variant="secondary" onClick={onCancel}>Cancel</Button>
        <Button variant="danger" onClick={onConfirm} data-testid="delete-confirm-btn">Delete</Button>
      </DialogFooter>
    </Dialog>
  );
}

// ── MyWeek Page ─────────────────────────────────────────────────────────────

export default function MyWeek() {
  const [weekOffset, setWeekOffset] = useState(0);
  const weekStartDate = getWeekStartDate(weekOffset);

  const bridge = useHostBridge();
  const currentUserId = bridge.context.authenticatedUser.id;

  const planApi = usePlanApi();
  const { data: planData, loading: planLoading, error: planError, refetch: refetchPlan } = useCurrentPlan(weekStartDate);
  const { data: rcdoTree } = useRcdoTree();

  const [showHistory, setShowHistory] = useState(false);
  const { data: planHistory, loading: historyLoading } = usePlanHistory(showHistory ? currentUserId : null);
  const [lineageCommitId, setLineageCommitId] = useState<string | null>(null);
  const { data: lineage, loading: lineageLoading } = useCarryForwardLineage(lineageCommitId);

  const ticketApi = useTicketApi();
  const [ticketFormVisible, setTicketFormVisible] = useState(false);
  const [ticketFormInitialValues, setTicketFormInitialValues] = useState<Partial<CreateTicketPayload>>({});

  type FormMode = "create" | "edit" | null;
  const [formMode, setFormMode] = useState<FormMode>(null);
  const [editingCommit, setEditingCommit] = useState<CommitResponse | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<CommitResponse | null>(null);
  const [actionError, setActionError] = useState<string | null>(null);
  const [lockLoading, setLockLoading] = useState(false);
  const [showPreLockValidation, setShowPreLockValidation] = useState(false);
  const [lockValidationErrors, setLockValidationErrors] = useState<LockValidationError[]>([]);
  const [showLockConfirm, setShowLockConfirm] = useState(false);

  type ScopeChangeMode = "add" | "edit" | "remove" | null;
  const [scopeChangeMode, setScopeChangeMode] = useState<ScopeChangeMode>(null);
  const [scopeChangeTargetCommit, setScopeChangeTargetCommit] = useState<CommitResponse | null>(null);
  const [pendingEditPayload, setPendingEditPayload] = useState<UpdateCommitPayload | null>(null);
  const [pendingCreatePayload, setPendingCreatePayload] = useState<CreateCommitPayload | null>(null);
  const [scopeChangeSaving, setScopeChangeSaving] = useState(false);
  const [scopeChangeEvents, setScopeChangeEvents] = useState<ScopeChangeEventResponse[]>([]);
  const [showTimeline, setShowTimeline] = useState(false);

  const plan = planData?.plan;
  const commits = useMemo(() => planData?.commits ?? [], [planData]);
  const effectivePreLockErrors = useMemo(() => getEffectivePreLockErrors(commits, lockValidationErrors), [commits, lockValidationErrors]);
  const isDraft = plan?.state === "DRAFT";
  const isLocked = plan?.state === "LOCKED";

  // ── Handlers ──────────────────────────────────────────────────────────────

  const handleOpenCreate = useCallback(() => {
    if (isLocked) { setScopeChangeMode("add"); setScopeChangeTargetCommit(null); setPendingCreatePayload(null); }
    else { setFormMode("create"); setEditingCommit(null); }
    setActionError(null);
  }, [isLocked]);

  const handleOpenEdit = useCallback((commit: CommitResponse) => {
    setFormMode("edit"); setEditingCommit(commit); setActionError(null);
  }, []);

  const handleFormCancel = useCallback(() => { setFormMode(null); setEditingCommit(null); }, []);

  const handleCreateCommit = useCallback(async (payload: CreateCommitPayload) => {
    if (!plan) return;
    if (isLocked) { setPendingCreatePayload(payload); setScopeChangeMode("add"); setScopeChangeTargetCommit(null); setFormMode(null); return; }
    await planApi.createCommit(plan.id, payload);
    refetchPlan(); setFormMode(null);
  }, [plan, isLocked, planApi, refetchPlan]);

  const handleUpdateCommit = useCallback(async (payload: UpdateCommitPayload) => {
    if (!plan || !editingCommit) return;
    if (isLocked) { setPendingEditPayload(payload); setScopeChangeMode("edit"); setScopeChangeTargetCommit(editingCommit); setFormMode(null); setEditingCommit(null); return; }
    await planApi.updateCommit(plan.id, editingCommit.id, payload);
    refetchPlan(); setFormMode(null); setEditingCommit(null);
  }, [plan, editingCommit, isLocked, planApi, refetchPlan]);

  const handleDeleteRequest = useCallback((commitId: string) => {
    const commit = commits.find((c) => c.id === commitId);
    if (!commit) return;
    if (isLocked) { setScopeChangeMode("remove"); setScopeChangeTargetCommit(commit); }
    else { setDeleteTarget(commit); }
  }, [commits, isLocked]);

  const handleDeleteConfirm = useCallback(async () => {
    if (!plan || !deleteTarget) return;
    try { await planApi.deleteCommit(plan.id, deleteTarget.id); refetchPlan(); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Delete failed"); }
    finally { setDeleteTarget(null); }
  }, [plan, deleteTarget, planApi, refetchPlan]);

  const handleReorder = useCallback(async (orderedIds: string[]) => {
    if (!plan) return;
    try { await planApi.reorderCommits(plan.id, orderedIds); refetchPlan(); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Reorder failed"); }
  }, [plan, planApi, refetchPlan]);

  const handleCreateTicketFromCommit = useCallback((commit: CommitResponse) => {
    const teamId = bridge.context.currentTeam?.id;
    setTicketFormInitialValues({
      title: commit.title,
      ...(commit.description ? { description: commit.description } : {}),
      ...(commit.rcdoNodeId ? { rcdoNodeId: commit.rcdoNodeId } : {}),
      ...(commit.estimatePoints != null ? { estimatePoints: commit.estimatePoints } : {}),
      reporterUserId: currentUserId,
      ...(teamId ? { teamId } : {}),
    });
    setTicketFormVisible(true);
  }, [currentUserId, bridge]);

  const handleTicketFormSubmit = useCallback(async (payload: CreateTicketPayload) => {
    await ticketApi.createTicket(payload);
    setTicketFormVisible(false); setTicketFormInitialValues({});
  }, [ticketApi]);

  const handleLockButtonClick = useCallback(() => {
    setShowPreLockValidation(true); setLockValidationErrors([]); setShowLockConfirm(false);
  }, []);

  const handlePreLockContinue = useCallback(() => { setShowLockConfirm(true); }, []);

  const handleLock = useCallback(async () => {
    if (!plan) return;
    setLockLoading(true); setActionError(null);
    try {
      const response = await planApi.lockPlan(plan.id);
      if (!response.success) { setLockValidationErrors(response.errors ?? []); setShowLockConfirm(false); return; }
      setShowPreLockValidation(false); setShowLockConfirm(false); setLockValidationErrors([]); refetchPlan();
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "Lock failed"); setShowLockConfirm(false);
    } finally { setLockLoading(false); }
  }, [plan, planApi, refetchPlan]);

  const handleScopeChangeConfirm = useCallback(async (reason: string) => {
    if (!plan) return;
    setScopeChangeSaving(true); setActionError(null);
    try {
      if (scopeChangeMode === "add" && pendingCreatePayload) {
        const result = await planApi.applyScopeChange(plan.id, { action: "ADD", reason, commitData: pendingCreatePayload });
        setScopeChangeEvents(result.events);
      } else if (scopeChangeMode === "remove" && scopeChangeTargetCommit) {
        const result = await planApi.applyScopeChange(plan.id, { action: "REMOVE", reason, commitId: scopeChangeTargetCommit.id });
        setScopeChangeEvents(result.events);
      } else if (scopeChangeMode === "edit" && scopeChangeTargetCommit && pendingEditPayload) {
        const result = await planApi.applyScopeChange(plan.id, { action: "EDIT", reason, commitId: scopeChangeTargetCommit.id, changes: pendingEditPayload });
        setScopeChangeEvents(result.events);
      }
      refetchPlan();
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "Scope change failed");
    } finally {
      setScopeChangeSaving(false); setScopeChangeMode(null); setScopeChangeTargetCommit(null);
      setPendingEditPayload(null); setPendingCreatePayload(null);
    }
  }, [plan, scopeChangeMode, pendingCreatePayload, pendingEditPayload, scopeChangeTargetCommit, planApi, refetchPlan]);

  const handleScopeChangeCancel = useCallback(() => {
    setScopeChangeMode(null); setScopeChangeTargetCommit(null); setPendingEditPayload(null); setPendingCreatePayload(null);
  }, []);

  const handleLoadTimeline = useCallback(async () => {
    if (!plan) return;
    try { const result = await planApi.getScopeChangeTimeline(plan.id); setScopeChangeEvents(result.events); setShowTimeline(true); }
    catch { /* non-critical */ }
  }, [plan, planApi]);

  function buildRcdoLabels(): Record<string, string> {
    const map: Record<string, string> = {};
    function traverse(nodes: typeof rcdoTree, path: string[] = []) {
      if (!nodes) return;
      for (const n of nodes) { const nextPath = [...path, n.title]; map[n.id] = nextPath.join(" > "); traverse(n.children, nextPath); }
    }
    traverse(rcdoTree ?? []);
    return map;
  }
  const rcdoLabels = buildRcdoLabels();

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div className="flex flex-col gap-4" data-testid="page-my-week">
      {/* Page header */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">My Week</h2>
        {isDraft && (
          <Button variant="primary" onClick={handleOpenCreate} data-testid="add-commit-btn">+ Add Commit</Button>
        )}
      </div>

      {/* Week selector */}
      <div data-testid="week-selector" className="flex items-center gap-2 flex-wrap">
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o - 1)} aria-label="Previous week" data-testid="prev-week-btn">
          <ChevronLeft className="h-4 w-4" />
        </Button>
        <span data-testid="week-label" className="font-semibold text-sm min-w-[14rem] text-center">{formatWeekLabel(weekStartDate)}</span>
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o + 1)} aria-label="Next week" data-testid="next-week-btn">
          <ChevronRight className="h-4 w-4" />
        </Button>
        {weekOffset !== 0 && (
          <Button variant="secondary" size="sm" onClick={() => setWeekOffset(0)} data-testid="current-week-btn">Today</Button>
        )}
      </div>

      {/* Loading */}
      {planLoading && (
        <div role="status" aria-label="Loading plan" data-testid="plan-loading" className="text-sm text-muted">Loading plan…</div>
      )}

      {/* Error */}
      {planError && (
        <div role="alert" data-testid="plan-error" className="rounded-default border border-red-200 bg-red-50 px-3 py-2.5 text-sm text-danger">
          Failed to load plan: {planError.message}
        </div>
      )}

      {/* Plan header */}
      {plan && (
        <Card data-testid="plan-header">
          <CardHeader>
            <div className="flex items-center gap-2.5">
              <PlanStateBadge state={plan.state} />
              <ComplianceBadge compliant={plan.compliant} />
            </div>
            <div className="flex items-center gap-2">
              {actionError && (
                <span role="alert" data-testid="plan-action-error" className="text-xs text-danger">{actionError}</span>
              )}
              {isDraft && (
                <Button variant="primary" size="sm" onClick={handleLockButtonClick} disabled={lockLoading} data-testid="lock-plan-btn">
                  <Lock className="h-3.5 w-3.5" />
                  {lockLoading ? "Locking…" : "Lock Plan"}
                </Button>
              )}
              {isLocked && (
                <Button variant="primary" size="sm" onClick={handleOpenCreate} data-testid="post-lock-add-commit-btn">+ Add Commit</Button>
              )}
              {(plan.state === "LOCKED" || plan.state === "RECONCILING") && (
                <span data-testid="reconcile-hint" className="text-sm text-muted">
                  Go to{" "}
                  <a href={`/weekly/reconcile/${plan.id}`} className="text-primary hover:underline">Reconcile</a>
                  {" "}to close this week.
                </span>
              )}
            </div>
          </CardHeader>
        </Card>
      )}

      {/* Auto-lock system banner */}
      {plan?.systemLockedWithErrors && (
        <div data-testid="auto-lock-banner" role="alert" className="flex items-start gap-2 rounded-default border border-amber-300 bg-amber-50 px-4 py-3 text-sm text-amber-900">
          <AlertTriangle className="h-4 w-4 mt-0.5 shrink-0 text-amber-500" aria-hidden="true" />
          <span><strong>System-locked with errors</strong> — this plan was automatically locked at the deadline. Some validation issues were present at lock time. Please review and reconcile.</span>
        </div>
      )}

      {/* Pre-lock validation panel */}
      {isDraft && showPreLockValidation && (
        <Card data-testid="pre-lock-validation-section">
          <CardHeader>
            <CardTitle>Pre-lock Validation</CardTitle>
            <Button variant="secondary" size="sm" type="button" onClick={() => setShowPreLockValidation(false)}>
              <X className="h-3.5 w-3.5" />Cancel
            </Button>
          </CardHeader>
          <CardContent>
            <PreLockValidationPanel errors={lockValidationErrors} commits={commits} />
            {effectivePreLockErrors.length === 0 && (
              <div className="mt-3.5 flex justify-end">
                <Button variant="primary" onClick={handlePreLockContinue} data-testid="pre-lock-continue-btn">
                  Continue to Lock →
                </Button>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Capacity meter */}
      {plan && <CapacityMeter commits={commits} budgetPoints={plan.capacityBudgetPoints} isManagerOverride={plan.capacityBudgetPoints !== 10} />}

      {/* Soft warnings */}
      {commits.length > 0 && <SoftWarningsPanel commits={commits} />}

      {/* Commit list */}
      {plan && (
        <CommitList
          commits={commits}
          planState={plan.state}
          onReorder={handleReorder}
          onEdit={handleOpenEdit}
          onDelete={handleDeleteRequest}
          rcdoLabels={rcdoLabels}
          onViewLineage={(commitId) => setLineageCommitId(commitId)}
          onCreateTicket={handleCreateTicketFromCommit}
        />
      )}

      {/* Scope change timeline */}
      {isLocked && scopeChangeEvents.length > 0 && (
        <section aria-labelledby="scope-timeline-heading">
          <h3 id="scope-timeline-heading" className="m-0 mb-2.5 text-sm font-bold">Post-lock Changes</h3>
          <ScopeChangeTimeline events={scopeChangeEvents} />
        </section>
      )}
      {isLocked && !showTimeline && (
        <Button variant="secondary" size="sm" type="button" onClick={() => void handleLoadTimeline()} data-testid="load-scope-timeline-btn" className="self-start">
          View scope-change history
        </Button>
      )}

      {/* CommitForm modals */}
      {formMode === "create" && plan && !isLocked && (
        <CommitForm mode="create" rcdoTree={rcdoTree ?? []} existingCommits={commits} onSubmit={handleCreateCommit} onCancel={handleFormCancel} />
      )}
      {formMode === "edit" && plan && editingCommit && (
        <CommitForm mode="edit" commit={editingCommit} rcdoTree={rcdoTree ?? []} existingCommits={commits} onSubmit={handleUpdateCommit} onCancel={handleFormCancel} />
      )}
      {scopeChangeMode === "add" && !pendingCreatePayload && plan && (
        <CommitForm mode="create" rcdoTree={rcdoTree ?? []} existingCommits={commits} onSubmit={async (payload) => { setPendingCreatePayload(payload); }} onCancel={handleScopeChangeCancel} />
      )}

      {/* Delete confirm */}
      {deleteTarget && !isLocked && (
        <DeleteConfirmDialog title={deleteTarget.title} onConfirm={handleDeleteConfirm} onCancel={() => setDeleteTarget(null)} />
      )}

      {/* Ticket form */}
      {ticketFormVisible && (
        <TicketForm mode="create" initialValues={ticketFormInitialValues} currentUserId={currentUserId} {...(bridge.context.currentTeam ? { currentTeamId: bridge.context.currentTeam.id } : {})} onSubmit={handleTicketFormSubmit} onCancel={() => { setTicketFormVisible(false); setTicketFormInitialValues({}); }} />
      )}

      {/* Lock confirm */}
      {showLockConfirm && plan && (
        <LockConfirmDialog commits={commits} capacityBudgetPoints={plan.capacityBudgetPoints} weekLabel={formatWeekLabel(weekStartDate)} onConfirm={() => void handleLock()} onCancel={() => setShowLockConfirm(false)} isLocking={lockLoading} />
      )}

      {/* Scope change dialogs */}
      {scopeChangeMode === "add" && pendingCreatePayload && (
        <ScopeChangeDialog action="ADD" commit={null} newCommitTitle={pendingCreatePayload.title} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}
      {scopeChangeMode === "edit" && scopeChangeTargetCommit && pendingEditPayload && (
        <ScopeChangeDialog action="EDIT" commit={scopeChangeTargetCommit} proposedChanges={pendingEditPayload as Partial<CommitResponse>} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}
      {scopeChangeMode === "remove" && scopeChangeTargetCommit && (
        <ScopeChangeDialog action="REMOVE" commit={scopeChangeTargetCommit} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}

      {/* Plan History */}
      <Card>
        <CardHeader>
          <CardTitle>Plan History</CardTitle>
          <Button variant="secondary" size="sm" type="button" onClick={() => setShowHistory((s) => !s)} data-testid="toggle-plan-history-btn">
            {showHistory ? "Hide" : "Show history"}
          </Button>
        </CardHeader>
        {showHistory && (
          <CardContent>
            <PlanHistoryView entries={planHistory ?? []} loading={historyLoading} />
          </CardContent>
        )}
      </Card>

      {/* Carry-forward lineage */}
      {lineageCommitId && (
        <Card data-testid="cf-lineage-section">
          <CardHeader>
            <CardTitle>Carry-forward Lineage</CardTitle>
            <Button variant="ghost" size="icon" type="button" onClick={() => setLineageCommitId(null)} aria-label="Close lineage" className="h-7 w-7">
              <X className="h-4 w-4" />
            </Button>
          </CardHeader>
          <CardContent>
            {lineage && <CarryForwardLineageView lineage={lineage} loading={lineageLoading} />}
            {lineageLoading && !lineage && (
              <div data-testid="cf-lineage-loading" role="status" className="text-sm text-muted">Loading lineage…</div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

/**
 * Team Week dashboard — manager view of the team's weekly commitments.
 * Route: /weekly/team/:teamId?
 */
import { useState, useCallback } from "react";
import { useParams } from "react-router-dom";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { cn } from "../lib/utils.js";
import { useHostBridge } from "../host/HostProvider.js";
import { useTeamApi, useTeamWeekView, useExceptionQueue } from "../api/teamHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { OverviewSection } from "../components/teamweek/OverviewSection.js";
import { ByPersonSection } from "../components/teamweek/ByPersonSection.js";
import { ByRcdoSection } from "../components/teamweek/ByRcdoSection.js";
import { ChessDistributionSection } from "../components/teamweek/ChessDistributionSection.js";
import { UncommittedWorkSection } from "../components/teamweek/UncommittedWorkSection.js";
import { ExceptionQueueSection } from "../components/teamweek/ExceptionQueueSection.js";
import { TeamHistoryView } from "../components/teamweek/TeamHistoryView.js";
import { useTeamHistory } from "../api/ticketHooks.js";
import type { ResolveExceptionPayload, AddCommentPayload } from "../api/teamTypes.js";

function getWeekStartDate(offsetWeeks = 0): string {
  const now = new Date();
  const dayOfWeek = now.getDay();
  const daysToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  const monday = new Date(now);
  monday.setDate(now.getDate() + daysToMonday + offsetWeeks * 7);
  return monday.toISOString().slice(0, 10);
}

function formatWeekLabel(isoDate: string): string {
  return `Week of ${new Date(`${isoDate}T00:00:00`).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}`;
}

type TabId = "overview" | "by-person" | "by-rcdo" | "chess" | "uncommitted" | "exceptions" | "history";
const TABS: Array<{ id: TabId; label: string }> = [
  { id: "overview", label: "Overview" },
  { id: "by-person", label: "By Person" },
  { id: "by-rcdo", label: "By RCDO" },
  { id: "chess", label: "Chess" },
  { id: "uncommitted", label: "Uncommitted" },
  { id: "exceptions", label: "Exceptions" },
  { id: "history", label: "History" },
];

export default function TeamWeek() {
  const { teamId: routeTeamId } = useParams<{ teamId?: string }>();
  const bridge = useHostBridge();
  const teamApi = useTeamApi();
  const teamId = routeTeamId ?? bridge.context.currentTeam?.id ?? null;
  const userId = bridge.context.authenticatedUser.id;

  const [weekOffset, setWeekOffset] = useState(0);
  const weekStartDate = getWeekStartDate(weekOffset);
  const [activeTab, setActiveTab] = useState<TabId>("overview");
  const [actionError, setActionError] = useState<string | null>(null);

  const { data: teamWeekData, loading: teamLoading, error: teamError, refetch: refetchTeamWeek } = useTeamWeekView(teamId, weekStartDate);
  const { data: exceptions, loading: exceptionsLoading, error: exceptionsError, refetch: refetchExceptions } = useExceptionQueue(teamId, weekStartDate);
  const { data: rcdoTree } = useRcdoTree();
  const { data: teamHistory, loading: historyLoading } = useTeamHistory(teamId);

  const handleResolveException = useCallback(async (exceptionId: string, payload: ResolveExceptionPayload) => {
    setActionError(null);
    try { await teamApi.resolveException(exceptionId, payload); refetchExceptions(); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Resolve failed"); throw err; }
  }, [teamApi, refetchExceptions]);

  const handleAddComment = useCallback(async (payload: AddCommentPayload) => {
    setActionError(null);
    try { await teamApi.addComment(payload); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Comment failed"); throw err; }
  }, [teamApi]);

  const handleQuickAssign = useCallback(async (ticketId: string, assigneeUserId: string) => {
    setActionError(null);
    try { await teamApi.quickAssignTicket(ticketId, { assigneeUserId }); refetchTeamWeek(); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Assign failed"); throw err; }
  }, [teamApi, refetchTeamWeek]);

  const unresolvedExceptions = exceptions?.filter((e) => !e.resolved).length ?? 0;

  return (
    <div className="flex flex-col gap-4" data-testid="page-team-week">
      {/* Page header */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">Team Week</h2>
        {teamWeekData && <span className="text-sm text-muted font-semibold">{teamWeekData.teamName}</span>}
      </div>

      {/* Week selector */}
      <div data-testid="team-week-selector" className="flex items-center gap-2 flex-wrap">
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o - 1)} aria-label="Previous week" data-testid="team-prev-week-btn">
          <ChevronLeft className="h-4 w-4" />
        </Button>
        <span data-testid="team-week-label" className="font-semibold text-sm min-w-[14rem] text-center">{formatWeekLabel(weekStartDate)}</span>
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o + 1)} aria-label="Next week" data-testid="team-next-week-btn">
          <ChevronRight className="h-4 w-4" />
        </Button>
        {weekOffset !== 0 && (
          <Button variant="secondary" size="sm" onClick={() => setWeekOffset(0)} data-testid="team-current-week-btn">Today</Button>
        )}
      </div>

      {!teamId && (
        <div data-testid="no-team-selected" className="py-8 text-center text-sm text-muted rounded-default border border-border bg-surface">
          No team selected. Please select a team to view the dashboard.
        </div>
      )}
      {teamId && (teamLoading || exceptionsLoading) && (
        <div role="status" aria-label="Loading team data" data-testid="team-week-loading" className="text-sm text-muted">Loading team data…</div>
      )}
      {(teamError ?? exceptionsError) && (
        <div role="alert" data-testid="team-week-error" className="rounded-default border border-red-200 bg-red-50 px-3 py-2 text-sm text-danger">
          Failed to load team data: {(teamError ?? exceptionsError)?.message}
        </div>
      )}
      {actionError && (
        <div role="alert" data-testid="team-action-error" className="rounded-default border border-red-200 bg-red-50 px-3 py-2 text-xs text-danger">{actionError}</div>
      )}

      {teamWeekData && (
        <>
          {/* Tab navigation */}
          <nav aria-label="Team week sections" className="flex gap-0 border-b-2 border-border flex-wrap">
            {TABS.map((tab) => (
              <button
                key={tab.id}
                type="button"
                role="tab"
                aria-selected={activeTab === tab.id}
                onClick={() => setActiveTab(tab.id)}
                data-testid={`tab-${tab.id}`}
                className={cn(
                  "px-4 py-2 border-none border-b-2 -mb-0.5 bg-transparent cursor-pointer text-sm font-medium transition-colors",
                  activeTab === tab.id ? "border-b-primary font-bold text-primary" : "border-b-transparent text-muted hover:text-foreground",
                )}
                style={{ borderBottom: activeTab === tab.id ? "2px solid var(--color-primary)" : "2px solid transparent" }}
              >
                {tab.label}
                {tab.id === "exceptions" && unresolvedExceptions > 0 && (
                  <span className="ml-1.5 text-[0.6rem] font-bold px-1 py-px rounded-full bg-red-100 text-red-700">{unresolvedExceptions}</span>
                )}
              </button>
            ))}
          </nav>

          {/* Tab panels */}
          <div role="tabpanel" aria-label={activeTab} data-testid={`panel-${activeTab}`}>
            {activeTab === "overview" && <OverviewSection complianceSummary={teamWeekData.complianceSummary} memberViews={teamWeekData.memberViews} exceptions={exceptions ?? []} />}
            {activeTab === "by-person" && <ByPersonSection memberViews={teamWeekData.memberViews} complianceSummary={teamWeekData.complianceSummary} />}
            {activeTab === "by-rcdo" && <ByRcdoSection rcdoRollup={teamWeekData.rcdoRollup} rcdoTree={rcdoTree ?? []} memberViews={teamWeekData.memberViews} />}
            {activeTab === "chess" && <ChessDistributionSection chessDistribution={teamWeekData.chessDistribution} />}
            {activeTab === "uncommitted" && <UncommittedWorkSection assignedTickets={teamWeekData.uncommittedAssignedTickets} unassignedTickets={teamWeekData.uncommittedUnassignedTickets} onQuickAssign={handleQuickAssign} />}
            {activeTab === "exceptions" && <ExceptionQueueSection exceptions={exceptions ?? []} actorUserId={userId} onResolve={handleResolveException} onAddComment={handleAddComment} />}
            {activeTab === "history" && <TeamHistoryView entries={teamHistory?.entries ?? []} loading={historyLoading} />}
          </div>
        </>
      )}
    </div>
  );
}

import {
  createContext,
  useContext,
  type ReactNode,
} from "react";
import type {
  HostContext,
  DesignTokens,
  NotificationBridge,
  TelemetryCallback,
  NavigationBridge,
} from "@weekly-commit/shared";

export interface HostBridge {
  readonly context: HostContext;
  readonly tokens: DesignTokens;
  readonly notifications: NotificationBridge;
  readonly telemetry: TelemetryCallback;
  readonly navigation: NavigationBridge;
}

const HostBridgeContext = createContext<HostBridge | null>(null);

export function useHostBridge(): HostBridge {
  const ctx = useContext(HostBridgeContext);
  if (ctx === null) {
    throw new Error("useHostBridge must be used within a HostProvider");
  }
  return ctx;
}

export function useHostContext(): HostContext {
  return useHostBridge().context;
}

interface HostProviderProps {
  readonly bridge: HostBridge;
  readonly children: ReactNode;
}

/**
 * Provides the host bridge to the entire weeklyCommit remote tree.
 * In production the PA host mounts this with real bridge implementations.
 * In standalone dev/test use MockHostProvider instead.
 */
export function HostProvider({ bridge, children }: HostProviderProps) {
  return (
    <HostBridgeContext.Provider value={bridge}>
      {children}
    </HostBridgeContext.Provider>
  );
}

