function renderPage(teamId?: string) {
  const path = teamId ? `/team/${teamId}` : "/team";
  const routePath = teamId ? "/team/:teamId" : "/team";
  return render(
    <MemoryRouter initialEntries={[path]}>
      <MockHostProvider>
