function makePlanState(
  plan: PlanResponse,
  commits: CommitResponse[] = [],
): ReturnType<typeof useCurrentPlan> {
  return {
    data: { plan, commits, totalPoints: commits.reduce((s, c) => s + (c.estimatePoints ?? 0), 0) },
    loading: false,
    error: null,
    refetch: mockRefetch,
  };
}

