import type { ApiClient } from "./client.js";
import type {
  TicketResponse,
  TicketSummaryResponse,
  PagedTicketResponse,
  CreateTicketPayload,
  UpdateTicketPayload,
  TicketListParams,
  TicketStatus,
  WeeklyPlanHistoryEntry,
  CarryForwardLineageResponse,
  TeamHistoryResponse,
} from "./ticketTypes.js";

export function createTicketApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /**
     * GET /api/tickets — paged list with optional filters.
     */
    listTickets: (params: TicketListParams = {}): Promise<PagedTicketResponse> => {
      const qs = new URLSearchParams();
      if (params.status) qs.set("status", params.status);
      if (params.assigneeUserId) qs.set("assigneeUserId", params.assigneeUserId);
      if (params.teamId) qs.set("teamId", params.teamId);
      if (params.rcdoNodeId) qs.set("rcdoNodeId", params.rcdoNodeId);
      if (params.targetWeek) qs.set("targetWeek", params.targetWeek);
      if (params.priority) qs.set("priority", params.priority);
      if (params.page != null) qs.set("page", String(params.page));
      if (params.pageSize != null) qs.set("pageSize", String(params.pageSize));
      if (params.sortBy) qs.set("sortBy", params.sortBy);
      if (params.sortDir) qs.set("sortDir", params.sortDir);
      const suffix = qs.toString() ? `?${qs.toString()}` : "";
      return client.get(`/tickets${suffix}`, { headers: actorHeader });
    },

    /** GET /api/tickets/{id} — full ticket detail. */
    getTicket: (ticketId: string): Promise<TicketResponse> =>
      client.get(`/tickets/${encodeURIComponent(ticketId)}`, {
        headers: actorHeader,
      }),

    /** POST /api/tickets — create a new ticket. */
    createTicket: (payload: CreateTicketPayload): Promise<TicketResponse> =>
      client.post("/tickets", payload, { headers: actorHeader }),

    /** PUT /api/tickets/{id} — partial update. */
    updateTicket: (
      ticketId: string,
      payload: UpdateTicketPayload,
    ): Promise<TicketResponse> =>
      client.put(`/tickets/${encodeURIComponent(ticketId)}`, payload, {
        headers: actorHeader,
      }),

    /** DELETE /api/tickets/{id} — soft-delete a ticket. */
    deleteTicket: (ticketId: string): Promise<void> =>
      client.delete(`/tickets/${encodeURIComponent(ticketId)}`, {
        headers: actorHeader,
      }),

    /**
     * PUT /api/tickets/{id}/status — dedicated status transition endpoint.
     * Records who made the change for the audit history.
     */
    transitionStatus: (
      ticketId: string,
      newStatus: TicketStatus,
      changedByUserId: string,
    ): Promise<TicketResponse> =>
      client.put(
        `/tickets/${encodeURIComponent(ticketId)}/status`,
        { status: newStatus, changedByUserId },
        { headers: actorHeader },
      ),

    /**
     * POST /api/tickets/from-commit — create a ticket pre-populated from a commit.
     * The backend copies title, description, RCDO link, estimate, and reporterUserId.
     */
    createTicketFromCommit: (
      commitId: string,
      planId: string,
      overrides?: Partial<CreateTicketPayload>,
    ): Promise<TicketResponse> =>
      client.post(
        "/tickets/from-commit",
        { commitId, planId, ...overrides },
        { headers: actorHeader },
      ),

    // ── Plan history ──────────────────────────────────────────────────────────

    /**
     * GET /api/users/{userId}/plan-history
     * Returns week-by-week plan history for a user.
     */
    getPlanHistory: (userId: string): Promise<WeeklyPlanHistoryEntry[]> =>
      client.get(`/users/${encodeURIComponent(userId)}/plan-history`, {
        headers: actorHeader,
      }),

    // ── Carry-forward lineage ─────────────────────────────────────────────────

    /**
     * GET /api/commits/{commitId}/carry-forward-lineage
     * Returns the full carry-forward provenance chain for a commit.
     */
    getCarryForwardLineage: (
      commitId: string,
    ): Promise<CarryForwardLineageResponse> =>
      client.get(
        `/commits/${encodeURIComponent(commitId)}/carry-forward-lineage`,
        { headers: actorHeader },
      ),

    // ── Team history ──────────────────────────────────────────────────────────

    /**
     * GET /api/teams/{teamId}/history
     * Returns weekly trend data for the team.
     */
    getTeamHistory: (teamId: string): Promise<TeamHistoryResponse> =>
      client.get(`/teams/${encodeURIComponent(teamId)}/history`, {
        headers: actorHeader,
      }),

    /**
     * GET /api/tickets/summary — minimal list (no pagination) for quick selects.
     * Used for commit→ticket linking in forms.
     */
    listTicketSummaries: (
      teamId?: string,
    ): Promise<TicketSummaryResponse[]> => {
      const qs = teamId ? `?teamId=${encodeURIComponent(teamId)}` : "";
      return client.get(`/tickets/summaries${qs}`, { headers: actorHeader });
    },
  };
}

export type TicketApi = ReturnType<typeof createTicketApi>;

/**
 * React hooks for Ticket, Plan-history, and Team-history data fetching.
 */

import { useMemo } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createTicketApi, type TicketApi } from "./ticketApi.js";
import type {
  PagedTicketResponse,
  TicketResponse,
  TicketListParams,
  WeeklyPlanHistoryEntry,
  CarryForwardLineageResponse,
  TeamHistoryResponse,
} from "./ticketTypes.js";

/**
 * Returns a stable TicketApi instance bound to the current user's auth token.
 */
export function useTicketApi(): TicketApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(
    () => {
      const client = createApiClient({
        baseUrl: "/api",
        getAuthToken: () => bridge.context.authToken,
      });
      return createTicketApi(client, authenticatedUser.id);
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [authToken, authenticatedUser.id],
  );
}

/**
 * Fetches a paged ticket list with optional filters.
 * The params object is serialized as the cache key.
 */
export function useTicketList(
  params: TicketListParams = {},
): QueryState<PagedTicketResponse> {
  const api = useTicketApi();
  const key = `tickets-${JSON.stringify(params)}`;
  return useQuery<PagedTicketResponse>(key, () => api.listTickets(params));
}

/**
 * Fetches full ticket detail for a single ticket.
 * Returns null data when ticketId is null.
 */
export function useTicket(
  ticketId: string | null,
): QueryState<TicketResponse | null> {
  const api = useTicketApi();
  const key = `ticket-${ticketId ?? "none"}`;
  return useQuery<TicketResponse | null>(
    key,
    () => (ticketId ? api.getTicket(ticketId) : Promise.resolve(null)),
    { enabled: ticketId !== null },
  );
}

/**
 * Fetches the week-by-week plan history for a user.
 */
export function usePlanHistory(
  userId: string | null,
): QueryState<WeeklyPlanHistoryEntry[]> {
  const api = useTicketApi();
  const key = `plan-history-${userId ?? "none"}`;
  return useQuery<WeeklyPlanHistoryEntry[]>(
    key,
    () => (userId ? api.getPlanHistory(userId) : Promise.resolve([])),
    { enabled: userId !== null },
  );
}

/**
 * Fetches the carry-forward lineage for a commit.
 */
export function useCarryForwardLineage(
  commitId: string | null,
): QueryState<CarryForwardLineageResponse | null> {
  const api = useTicketApi();
  const key = `cf-lineage-${commitId ?? "none"}`;
  return useQuery<CarryForwardLineageResponse | null>(
    key,
    () =>
      commitId
        ? api.getCarryForwardLineage(commitId)
        : Promise.resolve(null),
    { enabled: commitId !== null },
  );
}

/**
 * Fetches the weekly trend history for a team.
 */
export function useTeamHistory(
  teamId: string | null,
): QueryState<TeamHistoryResponse | null> {
  const api = useTicketApi();
  const key = `team-history-${teamId ?? "none"}`;
  return useQuery<TeamHistoryResponse | null>(
    key,
    () => (teamId ? api.getTeamHistory(teamId) : Promise.resolve(null)),
    { enabled: teamId !== null },
  );
}

