/**
 * Manager team AI summary service (PRD §17 capability 6).
 *
 * <p>
 * Generates a weekly summary citing:
 * <ul>
 * <li>Top RCDO branches by planned commitment.</li>
 * <li>Unresolved manager-review exceptions (cited by id).</li>
 * <li>Carry-forward patterns across team members.</li>
 * <li>Critical blocked items (King/Queen with BLOCKED tickets).</li>
 * </ul>
 *
 * <p>
 * Only visible to managers — access denied for non-managers.
 */
@Service
@Transactional
public class ManagerAiSummaryService {

	private static final Logger log = LoggerFactory.getLogger(ManagerAiSummaryService.class);

	private final AiProviderRegistry registry;
	private final AiSuggestionService suggestionService;
	private final TeamRepository teamRepo;
	private final TeamMembershipRepository membershipRepo;
	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final WorkItemRepository workItemRepo;
	private final RcdoNodeRepository rcdoNodeRepo;
	private final ManagerReviewExceptionRepository exceptionRepo;
	private final AuthorizationService authService;
	private final ObjectMapper objectMapper;

	public ManagerAiSummaryService(AiProviderRegistry registry, AiSuggestionService suggestionService,
			TeamRepository teamRepo, TeamMembershipRepository membershipRepo, WeeklyPlanRepository planRepo,
			WeeklyCommitRepository commitRepo, WorkItemRepository workItemRepo, RcdoNodeRepository rcdoNodeRepo,
			ManagerReviewExceptionRepository exceptionRepo, AuthorizationService authService,
			ObjectMapper objectMapper) {
		this.registry = registry;
		this.suggestionService = suggestionService;
		this.teamRepo = teamRepo;
		this.membershipRepo = membershipRepo;
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.workItemRepo = workItemRepo;
		this.rcdoNodeRepo = rcdoNodeRepo;
		this.exceptionRepo = exceptionRepo;
		this.authService = authService;
		this.objectMapper = objectMapper;
	}

	/**
	 * Returns the AI summary for a team week. Only accessible to managers.
	 *
	 * @param teamId
	 *            the team
	 * @param weekStart
	 *            the week start date
	 * @param callerId
	 *            the requesting user
	 * @return summary response
	 * @throws AccessDeniedException
	 *             if the caller is not a manager/admin
	 * @throws ResourceNotFoundException
	 *             if the team is not found
	 */
	public ManagerAiSummaryResponse getSummary(UUID teamId, LocalDate weekStart, UUID callerId) {
		teamRepo.findById(teamId).orElseThrow(() -> new ResourceNotFoundException("Team not found: " + teamId));

		// Privacy: only managers may access AI summaries
		UserRole callerRole = authService.getCallerRole(callerId);
		if (callerRole != UserRole.ADMIN && callerRole != UserRole.MANAGER) {
			throw new AccessDeniedException("Only managers may view AI team summaries");
		}

		if (!registry.isAiEnabled()) {
			return ManagerAiSummaryResponse.unavailable(teamId, weekStart);
		}

		// Gather team data
		List<TeamMembership> memberships = membershipRepo.findByTeamId(teamId);
		List<WeeklyPlan> plans = planRepo.findByTeamIdAndWeekStartDate(teamId, weekStart);

		// Collect all commits for this team-week
		List<WeeklyCommit> allCommits = new ArrayList<>();
		for (WeeklyPlan plan : plans) {
			allCommits.addAll(commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId()));
		}

		// Derive cited objects: unresolved exceptions
		List<ManagerReviewException> unresolvedExceptions = exceptionRepo
				.findByTeamIdAndWeekStartDateAndResolved(teamId, weekStart, false);
		List<UUID> unresolvedExceptionIds = unresolvedExceptions.stream().map(ManagerReviewException::getId).toList();

		// Carry-forward patterns
		List<String> carryForwardPatterns = deriveCarryForwardPatterns(allCommits);

		// Critical blocked items: King/Queen commits with BLOCKED tickets
		List<UUID> criticalBlockedItemIds = deriveCriticalBlockedItems(allCommits);

		// Top RCDO branches by planned points
		List<String> topRcdoBranches = deriveTopRcdoBranches(allCommits);

		// Build context for AI
		Map<String, Object> additionalCtx = new HashMap<>();
		additionalCtx.put("unresolvedExceptions", unresolvedExceptionIds.size());
		additionalCtx.put("carryForwardPatterns", carryForwardPatterns);
		additionalCtx.put("criticalBlockedItems", criticalBlockedItemIds.size());
		additionalCtx.put("memberCount", memberships.size());
		additionalCtx.put("topRcdoBranches", topRcdoBranches);

		AiContext context = new AiContext(AiContext.TYPE_TEAM_SUMMARY, callerId, null, null, Map.of(),
				Map.of("weekStart", weekStart.toString(), "teamId", teamId.toString()), List.of(), List.of(),
				additionalCtx);

		AiSuggestionResult result = registry.generateSuggestion(context);
		if (!result.available()) {
			return ManagerAiSummaryResponse.unavailable(teamId, weekStart);
		}

		String contextJson = toJson(additionalCtx);
		AiSuggestion stored = suggestionService.storeSuggestion(AiContext.TYPE_TEAM_SUMMARY, callerId, null, null,
				contextJson, result);

		String summaryText = parseSummaryText(result.payload(), memberships.size(), plans.size(), allCommits.size());

		return new ManagerAiSummaryResponse(true, stored.getId(), teamId, weekStart, summaryText, topRcdoBranches,
				unresolvedExceptionIds, carryForwardPatterns, criticalBlockedItemIds, result.modelVersion());
	}

	// -------------------------------------------------------------------------
	// Derived data helpers
	// -------------------------------------------------------------------------

	private List<String> deriveTopRcdoBranches(List<WeeklyCommit> commits) {
		Map<UUID, Integer> pointsByRcdo = new LinkedHashMap<>();
		for (WeeklyCommit c : commits) {
			if (c.getRcdoNodeId() == null) {
				continue;
			}
			int pts = c.getEstimatePoints() != null ? c.getEstimatePoints() : 0;
			pointsByRcdo.merge(c.getRcdoNodeId(), pts, Integer::sum);
		}

		return pointsByRcdo.entrySet().stream().sorted(Map.Entry.<UUID, Integer>comparingByValue().reversed()).limit(3)
				.map(e -> {
					RcdoNode node = rcdoNodeRepo.findById(e.getKey()).orElse(null);
					if (node == null) {
						return e.getKey().toString();
					}
					return node.getTitle() + " (" + e.getValue() + " pts)";
				}).toList();
	}

	private List<String> deriveCarryForwardPatterns(List<WeeklyCommit> commits) {
		long carryForwardCount = commits.stream().filter(c -> c.getCarryForwardStreak() > 0).count();
		if (carryForwardCount == 0) {
			return List.of();
		}
		List<String> patterns = new ArrayList<>();
		patterns.add(carryForwardCount + " commit(s) carried forward this week.");

		long repeatedCount = commits.stream().filter(c -> c.getCarryForwardStreak() >= 2).count();
		if (repeatedCount > 0) {
			patterns.add(repeatedCount + " commit(s) carried forward 2+ consecutive weeks.");
		}
		return patterns;
	}

	private List<UUID> deriveCriticalBlockedItems(List<WeeklyCommit> commits) {
		List<UUID> blocked = new ArrayList<>();
		for (WeeklyCommit c : commits) {
			if (c.getChessPiece() != ChessPiece.KING && c.getChessPiece() != ChessPiece.QUEEN) {
				continue;
			}
			if (c.getWorkItemId() == null) {
				continue;
			}
			workItemRepo.findById(c.getWorkItemId()).filter(wi -> wi.getStatus() == TicketStatus.BLOCKED)
					.ifPresent(wi -> blocked.add(wi.getId()));
		}
		return blocked;
	}

	private String parseSummaryText(String payload, int memberCount, int planCount, int commitCount) {
		try {
			JsonNode node = objectMapper.readTree(payload);
			JsonNode summaryNode = node.get("summaryText");
			if (summaryNode != null && !summaryNode.isNull() && !summaryNode.asText().isBlank()) {
				return summaryNode.asText();
			}
		} catch (JsonProcessingException e) {
			log.debug("Could not parse AI summary text: {}", e.getMessage());
		}
		// Fallback generated summary
		return "Team has " + memberCount + " member(s) with " + planCount + " plan(s) and " + commitCount
				+ " total commit(s) this week.";
	}

	private String toJson(Object obj) {
		try {
			return objectMapper.writeValueAsString(obj);
		} catch (JsonProcessingException e) {
			return "{}";
		}
	}
}

package com.weeklycommit.ai.service;

import com.weeklycommit.ai.dto.CommitLintRequest;
import com.weeklycommit.ai.dto.CommitLintResponse;
import com.weeklycommit.ai.dto.LintMessage;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.RcdoNodeStatus;
import com.weeklycommit.domain.repository.RcdoNodeRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Commit quality linting service (PRD §17 capability 2).
 *
 * <p>
 * Checks are split into:
 * <ul>
 * <li><b>hardValidation</b> — must be resolved before locking.</li>
 * <li><b>softGuidance</b> — informational only, never block locking.</li>
 * </ul>
 */
@Service
@Transactional(readOnly = true)
public class CommitLintService {

	/** Titles consisting only of these generic words are considered vague. */
	private static final Set<String> VAGUE_WORDS = Set.of("fix", "update", "change", "misc", "todo", "wip", "work",
			"task", "thing", "stuff", "item", "various", "general", "other");

	/** A plan with more than this many commits is considered over-fragmented. */
	private static final int FRAGMENTATION_THRESHOLD = 12;

	/** The minimum meaningful title length. */
	private static final int MIN_TITLE_LENGTH = 10;

	private final AiProviderRegistry registry;
	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final RcdoNodeRepository rcdoNodeRepo;

	public CommitLintService(AiProviderRegistry registry, WeeklyPlanRepository planRepo,
			WeeklyCommitRepository commitRepo, RcdoNodeRepository rcdoNodeRepo) {
		this.registry = registry;
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.rcdoNodeRepo = rcdoNodeRepo;
	}

	/**
	 * Runs commit quality checks for all commits in a plan.
	 *
	 * @param request
	 *            lint request with planId
	 * @return lint results categorised into hard and soft messages
	 */
	public CommitLintResponse lint(CommitLintRequest request) {
		if (!registry.isAiEnabled()) {
			return CommitLintResponse.unavailable();
		}

		WeeklyPlan plan = planRepo.findById(request.planId())
				.orElseThrow(() -> new ResourceNotFoundException("Plan not found: " + request.planId()));

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());

		List<LintMessage> hard = new ArrayList<>();
		List<LintMessage> soft = new ArrayList<>();

		// Plan-level checks
		if (commits.size() > FRAGMENTATION_THRESHOLD) {
			soft.add(new LintMessage("OVER_FRAGMENTED",
					"Plan has " + commits.size() + " commits — consider merging smaller items for focus.", null));
		}

		// Collect all titles for duplicate detection
		Map<String, UUID> seenTitles = new HashMap<>();

		for (WeeklyCommit commit : commits) {
			lintCommit(commit, hard, soft, seenTitles, plan);
		}

		// Store as ai_suggestion (rules-based lint, but stored for auditability)
		// We do not store the suggestion when AI is rule-only; the rules are
		// deterministic.
		// The AI provider is called for the soft-guidance enrichment part.
		enrichSoftGuidanceFromAi(request, commits, soft);

		return new CommitLintResponse(true, hard, soft);
	}

	// -------------------------------------------------------------------------
	// Per-commit checks
	// -------------------------------------------------------------------------

	private void lintCommit(WeeklyCommit commit, List<LintMessage> hard, List<LintMessage> soft,
			Map<String, UUID> seenTitles, WeeklyPlan plan) {

		String title = commit.getTitle() != null ? commit.getTitle().trim() : "";
		UUID id = commit.getId();

		// --- Hard: missing success criteria for King/Queen ---
		if ((commit.getChessPiece() == ChessPiece.KING || commit.getChessPiece() == ChessPiece.QUEEN)
				&& (commit.getSuccessCriteria() == null || commit.getSuccessCriteria().isBlank())) {
			hard.add(new LintMessage("MISSING_SUCCESS_CRITERIA",
					"Success criteria is required for " + commit.getChessPiece() + " commits.", id));
		}

		// --- Hard: duplicate / near-duplicate title ---
		String normalised = title.toLowerCase().replaceAll("\\s+", " ");
		if (seenTitles.containsKey(normalised)) {
			hard.add(new LintMessage("DUPLICATE_TITLE", "Duplicate commit title detected: \"" + title + "\".", id));
		} else {
			seenTitles.put(normalised, id);
		}

		// --- Soft: vague title ---
		if (title.length() < MIN_TITLE_LENGTH || isVagueTitle(title)) {
			soft.add(new LintMessage("VAGUE_TITLE",
					"Commit title \"" + title + "\" is vague or too short — be more specific.", id));
		}

		// --- Soft: parent-level RCDO when leaf node exists ---
		if (commit.getRcdoNodeId() != null) {
			boolean hasChildren = !rcdoNodeRepo.findByParentIdAndStatus(commit.getRcdoNodeId(), RcdoNodeStatus.ACTIVE)
					.isEmpty();
			if (hasChildren) {
				soft.add(new LintMessage("PARENT_LEVEL_RCDO",
						"Commit is linked to a parent RCDO node — consider linking to a leaf Outcome instead.", id));
			}
		}

		// --- Soft: estimate inconsistency (King/Queen with very small estimate) ---
		if ((commit.getChessPiece() == ChessPiece.KING || commit.getChessPiece() == ChessPiece.QUEEN)
				&& commit.getEstimatePoints() != null && commit.getEstimatePoints() <= 1) {
			soft.add(new LintMessage("ESTIMATE_INCONSISTENCY", "King/Queen commit has a very low estimate ("
					+ commit.getEstimatePoints() + " pt) — verify this reflects actual effort.", id));
		}
	}

	private boolean isVagueTitle(String title) {
		String[] words = title.toLowerCase().replaceAll("[^a-z\\s]", "").trim().split("\\s+");
		if (words.length == 0) {
			return true;
		}
		// All words are in the vague set → vague
		for (String word : words) {
			if (!VAGUE_WORDS.contains(word)) {
				return false;
			}
		}
		return true;
	}

	// -------------------------------------------------------------------------
	// AI enrichment for soft guidance
	// -------------------------------------------------------------------------

	/**
	 * Optionally calls the AI provider to enrich soft guidance. Failures are
	 * silently swallowed — lint always returns a result.
	 */
	private void enrichSoftGuidanceFromAi(CommitLintRequest request, List<WeeklyCommit> commits,
			List<LintMessage> soft) {
		try {
			Map<String, Object> planData = Map.of("commitCount", commits.size());
			AiContext ctx = new AiContext(AiContext.TYPE_COMMIT_LINT, request.userId(), request.planId(), null,
					Map.of(), planData, List.of(), List.of(), Map.of());
			registry.generateSuggestion(ctx);
			// We don't parse the AI output for lint — rules-based checks are authoritative.
			// AI call is made so providers can log/learn from the data.
		} catch (Exception ex) {
			// Swallow — lint never fails due to AI errors
		}
	}
}

/**
 * Route-level entry point exposed via Module Federation.
 * The PA host app imports this module to mount the weeklyCommit remote.
 *
 * Usage in host:
 *   const WeeklyCommitRoutes = React.lazy(() => import("weeklyCommit/Routes"));
 *   <WeeklyCommitRoutes bridge={hostBridge} />
 */
import { lazy, Suspense } from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import { HostProvider, type HostBridge } from "./host/HostProvider.js";
import { AppShell } from "./components/AppShell.js";

const MyWeek = lazy(() => import("./routes/MyWeek.js"));
const Reconcile = lazy(() => import("./routes/Reconcile.js"));
const TeamWeek = lazy(() => import("./routes/TeamWeek.js"));
const Tickets = lazy(() => import("./routes/Tickets.js"));
const Rcdos = lazy(() => import("./routes/Rcdos.js"));

function RouteFallback() {
  return (
    <div
      role="status"
      aria-label="Loading page"
      className="py-8 text-center text-sm text-muted"
    >
      Loading…
    </div>
  );
}

interface WeeklyCommitRoutesProps {
  /** Host bridge injected by the PA host app. */
  readonly bridge: HostBridge;
}

/**
 * All weekly-commit routes wrapped in the HostProvider and AppShell.
 * The host must wrap this component with its own BrowserRouter (or
 * pass a MemoryRouter for integration tests).
 */
export default function WeeklyCommitRoutes({
  bridge,
}: WeeklyCommitRoutesProps) {
  return (
    <HostProvider bridge={bridge}>
      <AppShell>
        <Suspense fallback={<RouteFallback />}>
          <Routes>
            <Route index element={<Navigate to="my-week" replace />} />
            <Route path="my-week" element={<MyWeek />} />
            <Route path="reconcile" element={<Reconcile />} />
            <Route path="reconcile/:planId" element={<Reconcile />} />
            <Route path="team" element={<TeamWeek />} />
            <Route path="team/:teamId" element={<TeamWeek />} />
            <Route path="tickets" element={<Tickets />} />
            <Route path="rcdos" element={<Rcdos />} />
          </Routes>
        </Suspense>
      </AppShell>
    </HostProvider>
  );
}

package com.weeklycommit.domain.entity;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import jakarta.validation.constraints.NotNull;
import java.time.Instant;
import java.util.UUID;
import org.hibernate.annotations.CreationTimestamp;

@Entity
@Table(name = "team_membership")
public class TeamMembership {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

	@NotNull
	@Column(name = "team_id", nullable = false)
	private UUID teamId;

	@NotNull
	@Column(name = "user_id", nullable = false)
	private UUID userId;

	@Column(nullable = false)
	private String role = "MEMBER";

	@CreationTimestamp
	@Column(name = "created_at", nullable = false, updatable = false)
	private Instant createdAt;

	public UUID getId() {
		return id;
	}

	public void setId(UUID id) {
		this.id = id;
	}

	public UUID getTeamId() {
		return teamId;
	}

	public void setTeamId(UUID teamId) {
		this.teamId = teamId;
	}

	public UUID getUserId() {
		return userId;
	}

	public void setUserId(UUID userId) {
		this.userId = userId;
	}

	public String getRole() {
		return role;
	}

	public void setRole(String role) {
		this.role = role;
	}

	public Instant getCreatedAt() {
		return createdAt;
	}
}

